fn repo_fixture_path(relative: &str) -> PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR"))
        .join("../..")
        .join(relative)
}

fn read_visual_edit_draft_fixture(relative: &str) -> String {
    fs::read_to_string(repo_fixture_path(relative))
        .unwrap_or_else(|error| panic!("{relative} reads: {error:#}"))
}

fn read_json_fixture(relative: &str) -> String {
    fs::read_to_string(repo_fixture_path(relative))
        .unwrap_or_else(|error| panic!("{relative} reads: {error:#}"))
}

fn read_repo_text(relative: &str) -> String {
    fs::read_to_string(repo_fixture_path(relative))
        .unwrap_or_else(|error| panic!("{relative} reads: {error:#}"))
}

fn js_function_source<'a>(source: &'a str, function_name: &str) -> &'a str {
    let marker = format!("function {function_name}");
    let start = source
        .find(&marker)
        .unwrap_or_else(|| panic!("{function_name} function exists"));
    let rest = &source[start..];
    let end = rest.find("\n  function ").unwrap_or(rest.len());
    &rest[..end]
}

#[test]
fn agent_role_model_v1_accepts_fixture_roles_and_boundaries() {
    let body = read_json_fixture("examples/multi-agent-pipeline-v1/agent-roles.fixture.json");
    let model = AgentRoleModel::from_json_str(&body).expect("agent role fixture validates");
    assert_eq!(model.schema_version, AGENT_ROLE_MODEL_SCHEMA_VERSION);
    assert_eq!(model.roles.len(), 9);
    assert!(model
        .roles
        .iter()
        .any(|role| role.role == "build-release-candidate-agent"
            && role.purpose.contains("Design-gate-only")));
    for role in &model.roles {
        assert!(!role.allowed_outputs.is_empty());
        assert!(!role.required_input_artifacts.is_empty());
        assert!(!role.required_evidence.is_empty());
        assert!(role.forbidden_actions.join(" ").contains("self-approval"));
        assert!(role.forbidden_actions.join(" ").contains("auto-apply"));
    }
    assert!(model
        .separation_requirements
        .iter()
        .any(|requirement| requirement.id == "no-self-review"));
    assert!(model
        .guardrails
        .join(" ")
        .contains("not hidden agent execution"));
    assert!(model
        .forbidden_actions
        .iter()
        .any(|action| action == "remote worker pool"));
    assert!(model.generated_state.tracked_fixture_only);
}

#[test]
fn ownership_policy_v1_accepts_fixture_scoped_policy_states() {
    for fixture in [
        "examples/multi-agent-pipeline-v1/ownership-policy.no-conflict.fixture.json",
        "examples/multi-agent-pipeline-v1/ownership-policy.shared-read.fixture.json",
        "examples/multi-agent-pipeline-v1/ownership-policy.exclusive-write.fixture.json",
        "examples/multi-agent-pipeline-v1/ownership-policy.conflict.fixture.json",
        "examples/multi-agent-pipeline-v1/ownership-policy.escalation.fixture.json",
    ] {
        let body = read_json_fixture(fixture);
        let policy = FileArtifactOwnershipPolicy::from_json_str(&body)
            .unwrap_or_else(|error| panic!("{fixture} validates: {error:#}"));
        assert_eq!(
            policy.schema_version,
            FILE_ARTIFACT_OWNERSHIP_POLICY_SCHEMA_VERSION
        );
        assert!(policy.generated_state.tracked_fixture_only);
        assert!(policy
            .generated_state
            .roots
            .iter()
            .any(|root| root == "runs/multi-agent-pipeline"));
        assert!(policy.boundary.contains("does not lock files"));
        assert!(policy
            .forbidden_actions
            .iter()
            .any(|action| action == "silent overwrite"));
        assert!(policy
            .forbidden_actions
            .iter()
            .any(|action| action == "auto-apply"));
        assert!(policy
            .forbidden_actions
            .iter()
            .any(|action| action == "browser command bridge"));
    }
}

