#[test]
fn agent_work_package_v1_rejects_unsupported_commands_conflicts_and_stale_drift() {
    let body =
        read_json_fixture("examples/multi-agent-pipeline-v1/agent-work-package.valid.fixture.json");
    let base: serde_json::Value = serde_json::from_str(&body).expect("work package json");

    let mut unsupported_command = base.clone();
    unsupported_command["verificationCommands"][0]["command"] = json!("curl https://example.test");
    unsupported_command["verificationCommands"][0]["argv"] =
        json!(["curl", "https://example.test"]);
    let command_error = AgentWorkPackage::from_json_str(&unsupported_command.to_string())
        .expect_err("unsupported verification command rejects package");
    assert!(command_error.to_string().contains("allowlist"));

    let mut missing_guardrail = base.clone();
    missing_guardrail["forbiddenActions"] = json!(["Do not execute commands from package"]);
    let guardrail_error = AgentWorkPackage::from_json_str(&missing_guardrail.to_string())
        .expect_err("missing forbidden guardrails reject package");
    assert!(guardrail_error.to_string().contains("forbiddenActions"));

    let mut ownership_conflict = base.clone();
    ownership_conflict["ownershipRefs"][0]["path"] =
        json!("examples/multi-agent-pipeline-v1/ownership-policy.conflict.fixture.json");
    let ownership_error = AgentWorkPackage::from_json_str(&ownership_conflict.to_string())
        .expect_err("ownership conflict refs reject package");
    assert!(ownership_error.to_string().contains("ownership conflict"));

    let mut stale_without_snapshot = base.clone();
    stale_without_snapshot["status"] = json!("stale");
    stale_without_snapshot["blockedReasons"] = json!(["refresh stale package evidence"]);
    stale_without_snapshot
        .as_object_mut()
        .unwrap()
        .remove("stateSnapshotRef");
    let stale_error = AgentWorkPackage::from_json_str(&stale_without_snapshot.to_string())
        .expect_err("stale package without snapshot rejects package");
    assert!(stale_error.to_string().contains("stateSnapshotRef"));
}

#[test]
fn agent_work_package_read_model_reports_status_blockers_and_malformed_state() {
    let ready = agent_work_package_read_model_from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-work-package.ready-for-review.fixture.json",
    ));
    assert_eq!(
        ready.schema_version,
        AGENT_WORK_PACKAGE_READ_MODEL_SCHEMA_VERSION
    );
    assert_eq!(
        ready.work_package_id,
        "work-package-scene-design-ready-review"
    );
    assert_eq!(ready.status, "ready-for-review");
    assert_eq!(ready.acceptance_criterion_count, 2);
    assert_eq!(ready.verification_command_count, 1);
    assert!(ready.blockers.is_empty());
    assert!(ready
        .ownership_refs
        .iter()
        .any(|path| path.contains("ownership-policy.no-conflict")));
    assert!(ready.handoff_target_path.contains("agent-handoff-v2.valid"));
    assert!(ready
        .boundary
        .contains("Read-only agent work package summary"));

    let blocked = agent_work_package_read_model_from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-work-package.blocked.fixture.json",
    ));
    assert_eq!(blocked.status, "blocked");
    assert!(blocked
        .blockers
        .iter()
        .any(|reason| reason.contains("ownership evidence")));

    let stale = agent_work_package_read_model_from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-work-package.stale.fixture.json",
    ));
    assert_eq!(stale.status, "stale");
    assert!(stale
        .state_snapshot_path
        .as_deref()
        .is_some_and(|path| path.contains("demo-state-snapshot.fixture.json")));

    let malformed = agent_work_package_read_model_from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-work-package.invalid.fixture.json",
    ));
    assert_eq!(malformed.status, "malformed");
    assert!(malformed
        .malformed_reasons
        .iter()
        .any(|reason| reason.contains("acceptanceCriteria")));
    assert!(malformed.boundary.contains("validation errors"));
}

#[test]
fn agent_shared_state_snapshot_v1_accepts_fixture_states_and_boundaries() {
    for (fixture, expected_status) in [
        (
            "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.fresh.fixture.json",
            AgentSharedStateSnapshotStatus::Fresh,
        ),
        (
            "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.stale.fixture.json",
            AgentSharedStateSnapshotStatus::Stale,
        ),
        (
            "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.partial.fixture.json",
            AgentSharedStateSnapshotStatus::Partial,
        ),
        (
            "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.missing.fixture.json",
            AgentSharedStateSnapshotStatus::Missing,
        ),
        (
            "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.malformed.fixture.json",
            AgentSharedStateSnapshotStatus::Malformed,
        ),
        (
            "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.conflicting.fixture.json",
            AgentSharedStateSnapshotStatus::Conflicting,
        ),
    ] {
        let snapshot = AgentSharedStateSnapshot::from_json_str(&read_json_fixture(fixture))
            .unwrap_or_else(|error| panic!("{fixture} validates: {error:#}"));
        assert_eq!(
            snapshot.schema_version,
            AGENT_SHARED_STATE_SNAPSHOT_SCHEMA_VERSION
        );
        assert_eq!(snapshot.status, expected_status);
        assert!(snapshot.project_manifest_hash.starts_with("sha256:"));
        assert!(!snapshot.scene_hashes.is_empty());
        assert!(!snapshot.recent_run_ids.is_empty());
        assert!(!snapshot.open_tasks.is_empty());
        assert!(!snapshot.ownership_map.is_empty());
        assert!(snapshot.before_context.is_some());
        assert!(snapshot.after_context.is_some());
        assert!(snapshot.generated_state.tracked_fixture_only);
        assert!(snapshot
            .generated_state
            .roots
            .iter()
            .any(|root| root == "runs/multi-agent-pipeline"));
        assert!(snapshot.boundary.contains("Read-only agent shared state"));
        assert!(snapshot.boundary.contains("does not execute commands"));
        assert!(snapshot.boundary.contains("does not mutate"));
        assert!(snapshot
            .boundary
            .contains("does not write trusted browser state"));
        assert!(snapshot.boundary.contains("does not repair stale state"));
        assert!(snapshot
            .forbidden_actions
            .iter()
            .any(|action| action == "hidden background agents"));
        assert!(snapshot
            .forbidden_actions
            .iter()
            .any(|action| action == "auto-apply"));
        assert!(snapshot
            .forbidden_actions
            .iter()
            .any(|action| action == "auto-merge"));
        assert!(snapshot
            .forbidden_actions
            .iter()
            .any(|action| action == "self-approval"));
    }
}

#[test]
fn agent_shared_state_snapshot_v1_rejects_invalid_and_status_drift() {
    let invalid = AgentSharedStateSnapshot::from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.invalid.fixture.json",
    ))
    .expect_err("invalid snapshot hash rejects");
    assert!(format!("{invalid:#}").contains("sha256"));

    let mut fresh_with_stale: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.fresh.fixture.json",
    ))
    .expect("snapshot json");
    fresh_with_stale["staleRefs"] = json!(["scene-main drift"]);
    let fresh_error = AgentSharedStateSnapshot::from_json_str(&fresh_with_stale.to_string())
        .expect_err("fresh snapshot cannot hide stale refs");
    assert!(format!("{fresh_error:#}").contains("fresh agent shared state snapshot"));

    let mut stale_without_refs: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.stale.fixture.json",
    ))
    .expect("snapshot json");
    stale_without_refs
        .as_object_mut()
        .expect("object")
        .remove("staleRefs");
    let stale_error = AgentSharedStateSnapshot::from_json_str(&stale_without_refs.to_string())
        .expect_err("stale snapshot requires stale refs");
    assert!(format!("{stale_error:#}").contains("requires staleRefs"));

    let mut unsafe_boundary: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.fresh.fixture.json",
    ))
    .expect("snapshot json");
    unsafe_boundary["boundary"] = json!("State snapshot can repair stale state.");
    let boundary_error = AgentSharedStateSnapshot::from_json_str(&unsafe_boundary.to_string())
        .expect_err("unsafe snapshot boundary rejects");
    assert!(format!("{boundary_error:#}").contains("read-only"));
}

#[test]
fn compare_snapshot_ownership_reports_current_duplicate_owner_collision() {
    let owner_ref = |owner: &str, id: &str, path: &str| AgentSharedStateSnapshotOwnership {
        owner: owner.to_string(),
        artifact_refs: vec![AuthoringLoopArtifactRef {
            id: id.to_string(),
            path: path.to_string(),
            description: None,
        }],
    };
    // Current state assigns the same artifact path to two distinct owners.
    let observed = vec![owner_ref("agent-a", "doc", "docs/shared.md")];
    let current = vec![
        owner_ref("agent-a", "doc", "docs/shared.md"),
        owner_ref("agent-b", "doc-dup", "docs/shared.md"),
    ];
    let mut stale_refs = Vec::new();
    let mut missing_refs = Vec::new();
    let mut conflicting_refs = Vec::new();
    compare_snapshot_ownership(
        &observed,
        &current,
        &mut stale_refs,
        &mut missing_refs,
        &mut conflicting_refs,
    );
    assert!(
        conflicting_refs.iter().any(|reference| reference
            .contains("docs/shared.md conflicting: current state assigns multiple owners")),
        "duplicate current owner path must be reported as conflicting: {conflicting_refs:?}"
    );
}

#[test]
fn agent_shared_state_snapshot_staleness_detection_reports_current_drift() {
    let snapshot = AgentSharedStateSnapshot::from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-shared-state-snapshot.fresh.fixture.json",
    ))
    .expect("snapshot fixture validates");
    let current = AgentSharedStateSnapshotCurrentState::from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-shared-state-current-state.fixture.json",
    ))
    .expect("current-state fixture validates");
    let fresh_report = snapshot.detect_staleness_against(&current);
    assert_eq!(fresh_report.status, AgentSharedStateSnapshotStatus::Fresh);
    assert!(fresh_report.stale_refs.is_empty());
    assert!(fresh_report.missing_refs.is_empty());
    assert!(fresh_report.conflicting_refs.is_empty());
    assert!(fresh_report.boundary.contains("Read-only"));
    assert!(fresh_report.boundary.contains("without executing commands"));
    assert!(fresh_report.boundary.contains("repairing stale state"));

    let drifted_current = AgentSharedStateSnapshotCurrentState::from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-shared-state-current-state.drift.fixture.json",
    ))
    .expect("drift current-state fixture validates");
    let drift_report = snapshot.detect_staleness_against(&drifted_current);
    assert_eq!(
        drift_report.status,
        AgentSharedStateSnapshotStatus::Conflicting
    );
    assert!(drift_report
        .stale_refs
        .iter()
        .any(|reference| reference.contains("projectManifestHash stale")));
    assert!(drift_report
        .stale_refs
        .iter()
        .any(|reference| reference.contains("sceneHashes.scene-main hash stale")));
    assert!(drift_report
        .stale_refs
        .iter()
        .any(|reference| reference.contains("tilemapHashes.tilemap-main stale")));
    assert!(drift_report
        .stale_refs
        .iter()
        .any(|reference| reference.contains("openTasks.task-regression-refresh stale")));
    assert!(drift_report
        .missing_refs
        .iter()
        .any(|reference| reference.contains("sceneHashes.scene-new missing")));
    assert!(drift_report
        .missing_refs
        .iter()
        .any(|reference| reference.contains("openTasks.task-new-current missing")));
    assert!(drift_report
            .missing_refs
            .iter()
            .any(|reference| reference.contains("ownershipMap.examples/multi-agent-pipeline-v1/qa-worker-assignment.valid.fixture.json missing")));
    assert!(drift_report
        .conflicting_refs
        .iter()
        .any(|reference| reference.contains("observed owner designer, current owner qa-agent")));
}

