#[test]
fn studio_pipeline_inspection_links_agent_decision_ledgers() {
    let active: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-decision-ledger.valid.fixture.json",
    ))
    .expect("active ledger json");
    let stale: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-decision-ledger.stale.fixture.json",
    ))
    .expect("stale ledger json");
    let malformed: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-decision-ledger.malformed.fixture.json",
    ))
    .expect("malformed ledger json");
    let append_violation: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/agent-decision-ledger.append-only-violation.fixture.json",
    ))
    .expect("append-only violation ledger json");
    let model = studio_multi_agent_pipeline_inspection_read_model_from_json_str(
        &json!({
            "agentDecisionLedgers": [active, stale, malformed, append_violation]
        })
        .to_string(),
    );
    let decisions = model
        .sections
        .iter()
        .find(|section| section.id == "decision-ledger")
        .expect("decision-ledger section");
    assert_eq!(decisions.status, "malformed");
    assert_eq!(decisions.item_count, 8);
    assert!(decisions
        .blockers
        .iter()
        .any(|reason| reason.contains("stale regression lane evidence")));
    assert!(decisions
        .blockers
        .iter()
        .any(|reason| reason.contains("append-only sequence")));
    assert!(decisions
        .malformed_reasons
        .iter()
        .any(|reason| reason.contains("decision-002 missing refreshed evidence refs")));
    assert_eq!(model.status, "malformed");

    let missing = studio_multi_agent_pipeline_inspection_read_model_from_json_str(
        &json!({ "agentDecisionLedgers": [] }).to_string(),
    );
    let missing_decisions = missing
        .sections
        .iter()
        .find(|section| section.id == "decision-ledger")
        .expect("missing decision-ledger section");
    assert_eq!(missing_decisions.status, "missing");
}

#[test]
fn agent_decision_ledger_doc_audits_generated_state_and_governance() {
    let doc = read_repo_text("docs/agent-decision-ledger-v1.md");
    for required in [
        "schemaVersion: agent-decision-ledger-v1",
        "append-only local audit evidence",
        "does not execute commands",
        "does not spawn agents",
        "does not apply changes",
        "does not merge changes",
        "does not write trusted browser state",
        "browser command bridges",
        "auto-apply",
        "auto-merge",
        "self-approve",
        "hidden background agents",
        "production readiness",
        "Godot replacement",
        "Generated decision ledgers",
        "Issues #1 and #23 must remain open",
    ] {
        assert!(
            doc.contains(required),
            "agent decision ledger doc missing {required}"
        );
    }
    for forbidden in [
        "autonomously complete arbitrary games",
        "production-ready game engine",
        "replace Godot",
        "browser command bridge controls are allowed",
        "self approval is allowed",
    ] {
        assert!(
            !doc.to_ascii_lowercase()
                .contains(&forbidden.to_ascii_lowercase()),
            "doc must not contain forbidden claim: {forbidden}"
        );
    }
}

#[test]
fn production_evidence_bundle_v1_accepts_fixture_states_and_boundaries() {
    for (fixture, expected_status) in [
            (
                "examples/multi-agent-pipeline-v1/production-evidence-bundle.complete.fixture.json",
                ProductionEvidenceBundleStatus::Complete,
            ),
            (
                "examples/multi-agent-pipeline-v1/production-evidence-bundle.partial.fixture.json",
                ProductionEvidenceBundleStatus::Partial,
            ),
            (
                "examples/multi-agent-pipeline-v1/production-evidence-bundle.blocked.fixture.json",
                ProductionEvidenceBundleStatus::Blocked,
            ),
            (
                "examples/multi-agent-pipeline-v1/production-evidence-bundle.stale.fixture.json",
                ProductionEvidenceBundleStatus::Stale,
            ),
            (
                "examples/multi-agent-pipeline-v1/production-evidence-bundle.unresolved-conflict.fixture.json",
                ProductionEvidenceBundleStatus::UnresolvedConflict,
            ),
            (
                "examples/multi-agent-pipeline-v1/production-evidence-bundle.missing-review.fixture.json",
                ProductionEvidenceBundleStatus::MissingReview,
            ),
        ] {
            let bundle = ProductionEvidenceBundle::from_json_str(&read_json_fixture(fixture))
                .unwrap_or_else(|error| panic!("{fixture} validates: {error:#}"));
            assert_eq!(bundle.schema_version, PRODUCTION_EVIDENCE_BUNDLE_SCHEMA_VERSION);
            assert_eq!(bundle.status, expected_status);
            assert!(!bundle.work_package_refs.is_empty());
            assert!(!bundle.handoff_refs.is_empty());
            assert!(!bundle.review_decision_refs.is_empty());
            assert!(!bundle.qa_result_refs.is_empty());
            assert!(!bundle.performance_regression_refs.is_empty());
            assert!(!bundle.decision_ledger_refs.is_empty());
            assert!(!bundle.outcome_refs.is_empty());
            assert_eq!(bundle.lane_outputs.len(), 11);
            assert!(bundle.generated_state.tracked_fixture_only);
            assert!(bundle
                .generated_state
                .roots
                .iter()
                .any(|root| root == "runs/multi-agent-pipeline"));
            let forbidden = bundle.forbidden_actions.join(" ");
            for required in [
                "hidden background agents",
                "auto-apply",
                "auto-merge",
                "self-approval",
                "browser command bridge",
                "cloud orchestration",
            ] {
                assert!(
                    forbidden.contains(required),
                    "{fixture} missing forbidden boundary {required}"
                );
            }
            assert!(bundle.boundary.contains("does not execute commands"));
            assert!(bundle.boundary.contains("does not spawn agents"));
            assert!(bundle
                .boundary
                .contains("does not write trusted browser state"));
            assert!(bundle
                .boundary
                .contains("does not claim production readiness"));
            assert!(bundle
                .boundary
                .contains("does not claim Godot replacement"));
        }
}

#[test]
fn production_evidence_bundle_v1_rejects_malformed_and_overclaimed_fixtures() {
    let invalid = ProductionEvidenceBundle::from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/production-evidence-bundle.invalid.fixture.json",
    ))
    .expect_err("invalid bundle fixture rejects");
    let invalid_text = format!("{invalid:#}");
    assert!(
        invalid_text.contains("complete production evidence bundle")
            || invalid_text.contains("forbiddenActions"),
        "unexpected invalid bundle error: {invalid_text}"
    );

    let mut partial: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/production-evidence-bundle.partial.fixture.json",
    ))
    .expect("partial bundle json");
    partial["missingRefs"] = json!([]);
    let partial_error = ProductionEvidenceBundle::from_json_str(&partial.to_string())
        .expect_err("partial bundle without missingRefs rejects");
    assert!(format!("{partial_error:#}").contains("requires missingRefs"));

    let mut blocked_lane: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/production-evidence-bundle.complete.fixture.json",
    ))
    .expect("complete bundle json");
    blocked_lane["laneOutputs"][0]["status"] = json!("blocked");
    let lane_error = ProductionEvidenceBundle::from_json_str(&blocked_lane.to_string())
        .expect_err("blocked lane without blocker rejects");
    assert!(format!("{lane_error:#}").contains("blocked status requires blockedReasons"));
}

#[test]
fn production_evidence_bundle_v1_rejects_reference_and_lane_inconsistency() {
    let complete: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/production-evidence-bundle.complete.fixture.json",
    ))
    .expect("complete bundle json");

    let mut duplicate_id = complete.clone();
    duplicate_id["workPackageRefs"][0]["id"] = duplicate_id["taskBoardRef"]["id"].clone();
    let duplicate_error = ProductionEvidenceBundle::from_json_str(&duplicate_id.to_string())
        .expect_err("duplicate ref ids reject");
    assert!(format!("{duplicate_error:#}").contains("duplicate artifact ref id"));

    let mut mismatched_lane = complete.clone();
    mismatched_lane["laneOutputs"][0]["evidenceRefs"][0] = mismatched_lane["roleModelRef"].clone();
    let mismatched_error = ProductionEvidenceBundle::from_json_str(&mismatched_lane.to_string())
        .expect_err("lane evidence must match lane refs");
    assert!(format!("{mismatched_error:#}").contains("must match top-level refs"));

    let mut missing_lane = complete.clone();
    missing_lane["laneOutputs"]
        .as_array_mut()
        .expect("lane outputs")
        .pop();
    let missing_lane_error = ProductionEvidenceBundle::from_json_str(&missing_lane.to_string())
        .expect_err("missing lane rejects");
    assert!(format!("{missing_lane_error:#}").contains("missing lane"));

    let mut complete_with_partial_lane = complete.clone();
    complete_with_partial_lane["laneOutputs"][0]["status"] = json!("partial");
    let complete_lane_error =
        ProductionEvidenceBundle::from_json_str(&complete_with_partial_lane.to_string())
            .expect_err("complete bundle with partial lane rejects");
    assert!(format!("{complete_lane_error:#}").contains("requires all laneOutputs"));
}

