#[test]
fn scenario_coverage_v12_task_board_status_transitions_are_state_machine_only() {
    let input = fs::read_to_string(repo_fixture_path(
        "examples/authoring-loop-plan-fixtures/valid/pending.json",
    ))
    .expect("pending task board fixture reads");
    let plan = AuthoringLoopPlan::from_json_str(&input).expect("pending task board validates");

    let (running, update) = plan
        .update_step_status("run-baseline", AuthoringLoopStepStatus::Running)
        .expect("pending task can move to running");

    assert_eq!(update.loop_id, "fixture-loop-pending");
    assert_eq!(update.step_id, "run-baseline");
    assert_eq!(update.from, "pending");
    assert_eq!(update.to, "running");
    assert!(update.boundary.contains("does not execute commands"));
    assert!(update.boundary.contains("write plan files"));
    assert_eq!(running.steps[0].status, AuthoringLoopStepStatus::Running);
    assert_eq!(
        running.steps[0]
            .status_transition
            .as_ref()
            .expect("transition recorded")
            .from,
        AuthoringLoopStepStatus::Pending
    );

    let invalid_transition = AuthoringLoopPlan::from_json_str(include_str!(
        "../../../examples/authoring-loop-plan-fixtures/invalid/invalid-status-transition.json"
    ))
    .expect_err("pending cannot jump straight to completed");
    assert!(invalid_transition
        .to_string()
        .contains("invalid status transition"));

    let illegal_retry = running
        .update_step_status("run-baseline", AuthoringLoopStepStatus::Pending)
        .expect_err("running cannot silently return to pending without blocked/failed state");
    assert!(illegal_retry.to_string().contains("cannot transition"));
}

#[test]
fn scenario_coverage_v12_work_packages_and_ownership_block_conflicts() {
    let input = fs::read_to_string(repo_fixture_path(
        "examples/authoring-loop-plan-fixtures/valid/completed.json",
    ))
    .expect("completed work package fixture reads");
    let plan = AuthoringLoopPlan::from_json_str(&input).expect("completed work packages validate");

    assert_eq!(plan.steps.len(), 8);
    assert!(plan
        .steps
        .iter()
        .all(|step| !step.expected_artifacts.is_empty()
            || step.kind == AuthoringLoopStepKind::RecordReviewDecision));
    let apply = plan
        .steps
        .iter()
        .find(|step| step.kind == AuthoringLoopStepKind::ApplyAcceptedSceneMutation)
        .expect("apply work package exists");
    assert!(
        !apply.rollback_refs.is_empty(),
        "trusted mutation work packages keep rollback ownership evidence"
    );
    assert!(
        !apply.required_decisions.is_empty(),
        "apply work packages require accepted review evidence"
    );

    let mut duplicate_artifact =
        serde_json::from_str::<serde_json::Value>(&input).expect("fixture parses as value");
    duplicate_artifact["steps"][1]["expectedArtifacts"][0]["id"] = json!("baseline-run");
    let duplicate_error = AuthoringLoopPlan::from_json_str(&duplicate_artifact.to_string())
        .expect_err("two work packages cannot own the same artifact id");
    assert!(duplicate_error
        .to_string()
        .contains("duplicate authoring loop plan artifact id"));

    let duplicate_step = AuthoringLoopPlan::from_json_str(include_str!(
        "../../../examples/authoring-loop-plan-fixtures/invalid/duplicate-step-id.json"
    ))
    .expect_err("task board rejects duplicate ownership by step id");
    assert!(duplicate_step
        .to_string()
        .contains("duplicate authoring loop plan step id"));

    let incomplete_producer = AuthoringLoopPlan::from_json_str(include_str!(
        "../../../examples/authoring-loop-plan-fixtures/invalid/incomplete-input-producer.json"
    ))
    .expect_err("completed consumer cannot depend on failed producer output");
    assert!(incomplete_producer
        .to_string()
        .contains("input baseline-run is not produced by a completed step"));
}

#[test]
fn scenario_coverage_v12_snapshots_and_staleness_are_read_only_status_evidence() {
    let root = unique_temp_dir("scenario-coverage-v12-stale-snapshot");
    write_loop_dry_run_project(&root);
    let plan_path = write_loop_dry_run_plan(&root, "stale_project_id");
    let plan = read_loop_plan_from_path(&plan_path);

    let status = build_authoring_loop_status(&plan, &root).expect("status read model builds");
    assert_eq!(status.schema_version, AUTHORING_LOOP_STATUS_SCHEMA_VERSION);
    assert_eq!(status.status, "in-progress");
    assert!(status.boundary.contains("read-only inspection"));
    assert!(status.boundary.contains("does not execute"));
    assert!(status.steps.iter().any(|step| {
        step.missing_prerequisites
            .iter()
            .any(|missing| missing.contains("stale project context"))
    }));
    assert!(status
        .next_safe_action
        .contains("Resolve missing prerequisites"));

    let dry_run =
        build_authoring_loop_dry_run_summary_with_base(&plan, &root).expect("dry-run builds");
    assert_eq!(dry_run.status, "blocked");
    assert!(dry_run.boundary.contains("does not execute"));
    assert!(dry_run
        .missing_prerequisites
        .iter()
        .any(|missing| missing.contains("stale project context")));

    let bundle = build_authoring_loop_evidence_bundle(&plan, &root, &plan_path)
        .expect("bundle snapshot read model builds despite stale prereq");
    assert_eq!(
        bundle.schema_version,
        AUTHORING_LOOP_EVIDENCE_BUNDLE_SCHEMA_VERSION
    );
    assert!(bundle
        .boundary
        .contains("does not move artifacts, mutate source state"));
    assert!(
        bundle.generated_state.tracked_fixture_only,
        "generated task-board snapshots stay fixture-scoped"
    );

    fs::remove_dir_all(root).ok();
}

#[test]
fn build_release_candidate_agent_lane_design_gate_audits_release_boundaries() {
    let doc = read_repo_text("docs/build-release-candidate-agent-lane-design-gate-v1.md");
    for required in [
        "design gate only",
        "does not implement build",
        "release automation",
        "CI/CD automation",
        "native export",
        "public visibility",
        "credentialed commands",
        "network/install commands",
        "dependency mutation",
        "browser command bridges",
        "hidden background agents",
        "auto-apply",
        "auto-merge",
        "self-approval",
        "reviewer bypass",
        "generated-state audit",
        "conservative public wording audit",
        "issues #1 and #23 remain open",
        "hold",
        "needs-review",
        "ready-for-human-release-review",
        "does not execute commands",
        "does not supersede",
    ] {
        assert!(
            doc.contains(required),
            "build/release lane design doc missing {required}"
        );
    }
    for forbidden in [
        "this lane publishes",
        "automatically releases",
        "agents may sign",
        "native export is authorized",
        "is production-ready",
        "replace Godot",
        "browser command bridge is allowed",
        "self approval is allowed",
    ] {
        assert!(
            !doc.to_ascii_lowercase()
                .contains(&forbidden.to_ascii_lowercase()),
            "design doc must not contain forbidden claim: {forbidden}"
        );
    }
}

#[test]
fn scenario_coverage_v12_review_critic_qa_and_build_lanes_stay_separated() {
    let input = fs::read_to_string(repo_fixture_path(
        "examples/multi-agent-pipeline-v1/agent-roles.fixture.json",
    ))
    .expect("agent role fixture reads");
    let model = AgentRoleModel::from_json_str(&input).expect("role model validates");
    let roles = model
        .roles
        .iter()
        .map(|role| (role.role.as_str(), role))
        .collect::<BTreeMap<_, _>>();

    let reviewer = roles.get("reviewer").expect("reviewer role");
    assert!(reviewer
        .handoff_targets
        .iter()
        .any(|target| target == "critic"));
    assert!(reviewer
        .required_evidence
        .iter()
        .any(|evidence| evidence.contains("independent-review")));

    let critic = roles.get("critic").expect("critic role");
    assert!(critic
        .required_evidence
        .iter()
        .any(|evidence| evidence.contains("no-self-review")));

    let qa = roles.get("qa-agent").expect("qa role");
    assert!(qa
        .allowed_outputs
        .iter()
        .any(|output| output == "qa-report"));
    assert!(qa
        .required_evidence
        .iter()
        .any(|evidence| evidence.contains("generated-state-audit")));

    let performance = roles
        .get("performance-regression-agent")
        .expect("performance lane role");
    assert!(performance
        .allowed_outputs
        .iter()
        .any(|output| output == "performance-summary"));
    assert!(performance
        .forbidden_actions
        .iter()
        .any(|action| action.contains("production-safety-claim")));

    let build = roles
        .get("build-release-candidate-agent")
        .expect("build/release design-gate role");
    assert!(build.purpose.contains("does not publish"));
    assert!(build
        .forbidden_actions
        .iter()
        .any(|action| action.contains("publish")));

    let mut unsafe_model =
        serde_json::from_str::<serde_json::Value>(&input).expect("role fixture as value");
    unsafe_model["roles"][6]["allowedOutputs"]
        .as_array_mut()
        .unwrap()
        .push(json!("self-approval"));
    let error = AgentRoleModel::from_json_str(&unsafe_model.to_string())
        .expect_err("reviewer cannot advertise self-approval output");
    assert!(error
        .to_string()
        .contains("contains forbidden output authority"));
}

#[test]
fn scenario_coverage_v12_gate_lane_bundle_categorizes_review_regression_and_matrix() {
    let root = unique_temp_dir("scenario-coverage-v12-bundle-lanes");
    write_loop_dry_run_project(&root);
    let mut plan = AuthoringLoopPlan::from_json_str(include_str!(
        "../../../examples/authoring-loop-plan-fixtures/valid/completed.json"
    ))
    .expect("completed plan validates");
    let summarize = plan
        .steps
        .iter_mut()
        .find(|step| step.kind == AuthoringLoopStepKind::Summarize)
        .expect("summarize step");
    summarize.expected_artifacts.push(AuthoringLoopArtifactRef {
        id: "matrix-snapshot".to_string(),
        path: "runs/after/regression-matrix.json".to_string(),
        description: Some("regression lane matrix snapshot".to_string()),
    });

    let plan_path = root.join("loop-plan.json");
    fs::write(
        &plan_path,
        serde_json::to_string_pretty(&plan).expect("plan json"),
    )
    .expect("plan written");
    for step in &plan.steps {
        for artifact in &step.expected_artifacts {
            let path = root.join(&artifact.path);
            fs::create_dir_all(path.parent().expect("artifact parent")).expect("artifact dir");
            fs::write(path, "{}\n").expect("artifact file");
        }
    }

    let bundle =
        write_authoring_loop_evidence_bundle(&plan, &root, &plan_path).expect("bundle writes");

    assert_eq!(bundle.status, AuthoringLoopEvidenceBundleStatus::Completed);
    assert_eq!(bundle.runs.len(), 2);
    assert_eq!(bundle.comparisons.len(), 1);
    assert_eq!(bundle.proposals.len(), 1);
    assert_eq!(bundle.review_decisions.len(), 1);
    assert_eq!(bundle.transactions.len(), 1);
    assert_eq!(bundle.regression_promotions.len(), 1);
    assert_eq!(bundle.matrix_snapshots.len(), 1);
    assert_eq!(bundle.journal_summaries.len(), 1);
    assert!(bundle.missing_refs.is_empty());
    assert!(root
        .join("runs/authoring-loop-bundles/fixture-loop-completed/bundle.json")
        .is_file());

    let listed = list_authoring_loop_evidence_bundles(root.join("runs"))
        .expect("generated bundles list and validate refs");
    assert_eq!(listed.len(), 1);
    assert_eq!(listed[0].loop_id, "fixture-loop-completed");
    assert!(listed[0]
        .boundary
        .contains("does not move artifacts, mutate source state"));

    fs::remove_dir_all(root).ok();
}

#[test]
fn scenario_coverage_v12_read_model_compatibility_documents_generated_state_boundaries() {
    let root = unique_temp_dir("scenario-coverage-v12-read-model-compatibility");
    write_loop_dry_run_project(&root);
    let plan_path = write_loop_dry_run_plan(&root, "loop_project");
    let plan = read_loop_plan_from_path(&plan_path);
    let bundle = build_authoring_loop_evidence_bundle(&plan, &root, &plan_path)
        .expect("partial bundle read model builds without writing generated bundle state");
    let handoff_path = root.join("runs/agent-handoffs/temp-loop/handoff.json");
    let handoff = write_agent_handoff_contract_from_path(&plan_path, &handoff_path)
        .expect("handoff contract writes advisory generated state");

    assert_eq!(
        bundle.schema_version,
        AUTHORING_LOOP_EVIDENCE_BUNDLE_SCHEMA_VERSION
    );
    assert_eq!(
        handoff.schema_version,
        AGENT_HANDOFF_CONTRACT_SCHEMA_VERSION
    );
    assert!(bundle.generated_state.tracked_fixture_only);
    assert!(handoff.generated_state.tracked_fixture_only);
    assert!(bundle
        .generated_state
        .roots
        .iter()
        .any(|root| root == "runs"));
    assert!(
        !bundle.missing_refs.is_empty(),
        "compatibility read model preserves missing generated refs instead of fixing them"
    );

    let cockpit = build_studio_loop_cockpit_read_model(
        std::slice::from_ref(&bundle),
        std::slice::from_ref(&handoff),
        &[],
    );
    assert_eq!(cockpit.schema_version, STUDIO_LOOP_COCKPIT_SCHEMA_VERSION);
    assert!(cockpit.boundary.contains("does not execute commands"));
    assert!(cockpit.boundary.contains("write files"));
    assert_eq!(cockpit.loops.len(), 1);
    assert_eq!(cockpit.loops[0].loop_id, "temp-loop");
    assert_eq!(cockpit.loops[0].bundle_missing_refs, bundle.missing_refs);
    assert!(cockpit.loops[0]
        .allowed_commands
        .iter()
        .all(|command| command.boundary.contains("inert")
            || command.boundary.contains("does not execute")));
    assert!(cockpit.loops[0]
        .forbidden_actions
        .iter()
        .any(|action| action.contains("trusted state") || action.contains("browser")));
    assert!(cockpit.loops[0]
        .boundary
        .contains("does not move artifacts, mutate source state"));
    assert!(
        !root
            .join("runs/authoring-loop-bundles/temp-loop/bundle.json")
            .exists(),
        "Studio compatibility read model must not persist generated dashboard exports"
    );

    fs::remove_dir_all(root).ok();
}

#[test]
fn scenario_coverage_v12_decision_ledger_appends_review_and_critic_events() {
    let root = unique_temp_dir("scenario-coverage-v12-decision-ledger");
    fs::create_dir_all(&root).expect("ledger root");
    fs::write(root.join("ledger.jsonl"), "").expect("ledger file");

    let review = append_ledger_event(
        &root,
        "multi_agent.review_decision",
        "reviewer",
        json!({
            "decisionId": "review-001",
            "status": "accepted",
            "evidenceRefs": ["runs/review/evidence.json"],
            "boundary": "review metadata only; does not apply or merge"
        }),
    )
    .expect("review event appends");
    let critic = append_ledger_event(
        &root,
        "multi_agent.critic_finding",
        "critic",
        json!({
            "findingId": "critic-001",
            "status": "cleared",
            "evidenceRefs": ["runs/critic/evidence.json"],
            "boundary": "critic metadata only; does not apply or merge"
        }),
    )
    .expect("critic event appends");

    let events = read_ledger_events(&root).expect("ledger reads");
    assert_eq!(events.len(), 2);
    assert_eq!(events[0], review);
    assert_eq!(events[1], critic);
    assert_eq!(events[0]["actor"], json!("reviewer"));
    assert_eq!(events[1]["actor"], json!("critic"));
    assert!(fs::read_to_string(root.join("ledger.jsonl"))
        .expect("ledger text")
        .lines()
        .all(|line| line.contains("does not apply or merge")));

    fs::remove_dir_all(root).ok();
}

fn loop_evidence_bundle_value(status: &str, missing_refs: Vec<&str>) -> serde_json::Value {
    json!({
        "schemaVersion": "authoring-loop-evidence-bundle-v1",
        "loopId": "loop-bundle-fixture",
        "status": status,
        "plan": { "id": "loop-plan", "kind": "loop-plan", "path": "runs/loops/loop-plan.json" },
        "steps": [{
            "stepId": "run-baseline",
            "kind": "run-scenario-pack",
            "status": status,
            "outputs": [{ "id": "baseline-output", "kind": "step-output", "path": "runs/loops/baseline-output.json", "stepId": "run-baseline" }],
            "missingRefs": missing_refs,
        }],
        "runs": [
            { "id": "source-run", "kind": "run", "path": "runs/source/run.json" },
            { "id": "after-run", "kind": "run", "path": "runs/after/run.json" }
        ],
        "comparisons": [{ "id": "comparison", "kind": "comparison", "path": "runs/after/comparison.json" }],
        "proposals": [{ "id": "proposal", "kind": "proposal", "path": "runs/after/mutation-proposals.json" }],
        "reviewDecisions": [{ "id": "decision", "kind": "review-decision", "path": "runs/after/review-decisions.json" }],
        "transactions": [{ "id": "transaction", "kind": "transaction", "path": "runs/after/transactions/scene-edit.json" }],
        "regressionPromotions": [{ "id": "promotion", "kind": "regression-promotion", "path": "runs/after/regression-promotion.json" }],
        "matrixSnapshots": [{ "id": "matrix", "kind": "matrix-snapshot", "path": "runs/regression-matrix.json" }],
        "journalSummaries": [{ "id": "journal", "kind": "journal-summary", "path": "runs/after/journal.md" }],
        "missingRefs": missing_refs,
        "generatedState": { "roots": ["runs", "target", "dashboard-data"], "trackedFixtureOnly": true },
        "boundary": "Generated local index only; does not move artifacts, write source state, serve files, or add browser controls."
    })
}

fn write_bundle_ref_files(
    root: &Path,
    bundle: &AuthoringLoopEvidenceBundle,
    skip_id: Option<&str>,
) {
    for artifact in bundle.all_artifact_refs() {
        if skip_id == Some(artifact.id.as_str()) {
            continue;
        }
        let path = root.join(&artifact.path);
        fs::create_dir_all(path.parent().expect("bundle ref parent")).expect("bundle ref dir");
        fs::write(path, "{}\n").expect("bundle ref file");
    }
}

fn agent_handoff_value(status: &str) -> serde_json::Value {
    json!({
        "schemaVersion": "agent-handoff-contract-v1",
        "loopId": "handoff-loop",
        "currentStep": { "stepId": "compare-runs", "kind": "compare-runs", "status": status },
        "status": status,
        "nextSafeAction": "Inspect blockers and run the displayed CLI command manually after required decisions are satisfied.",
        "requiredDecisions": [],
        "blockers": if status == "blocked" || status == "failed" { json!(["missing comparison evidence"]) } else { json!([]) },
        "allowedCommands": [{
            "command": "cargo run -p ouroforge-cli -- loop status loop-plan.json",
            "argv": ["cargo", "run", "-p", "ouroforge-cli", "--", "loop", "status", "loop-plan.json"],
            "boundary": "inert display text only; browser does not execute"
        }],
        "forbiddenActions": ["Do not auto-apply mutations", "Do not auto-merge changes", "Do not execute commands from browser UI"],
        "evidenceRefs": [{ "id": "bundle", "path": "runs/authoring-loop-bundles/handoff-loop/bundle.json" }],
        "driftGuardrails": ["#1 remains open", "#23 remains open", "Generated artifacts stay untracked"],
        "generatedState": { "roots": ["runs", "target", "dashboard-data"], "trackedFixtureOnly": true },
        "boundary": "advisory evidence only; does not execute commands or grant authority beyond documented loop state"
    })
}

#[test]
fn agent_handoff_schema_accepts_complete_blocked_and_failed_states() {
    let complete = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&agent_handoff_value("completed")).expect("handoff json"),
    )
    .expect("completed handoff validates");
    assert_eq!(
        complete.schema_version,
        AGENT_HANDOFF_CONTRACT_SCHEMA_VERSION
    );
    assert_eq!(complete.status, AgentHandoffStatus::Completed);

    let blocked = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&agent_handoff_value("blocked")).expect("handoff json"),
    )
    .expect("blocked handoff validates with blockers");
    assert_eq!(blocked.status, AgentHandoffStatus::Blocked);
    assert_eq!(blocked.blockers, vec!["missing comparison evidence"]);

    let failed = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&agent_handoff_value("failed")).expect("handoff json"),
    )
    .expect("failed handoff validates with blockers");
    assert_eq!(failed.status, AgentHandoffStatus::Failed);
    assert!(failed.boundary.contains("does not execute"));

    // `stale` is an agent-handoff-v2-only status; the shared enum must not
    // leak it into the v1 contract's accepted set.
    let stale_error = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&agent_handoff_value("stale")).expect("handoff json"),
    )
    .expect_err("stale status must be rejected for agent-handoff-contract-v1");
    assert!(stale_error.to_string().contains("stale"));
}

#[test]
fn agent_handoff_schema_reports_missing_decision_and_unsafe_next_action() {
    let mut missing_decision = agent_handoff_value("blocked");
    missing_decision["requiredDecisions"] =
        json!([{ "id": "human-review", "kind": "human-review" }]);
    missing_decision["blockers"] = json!(["missing decision:human-review"]);
    let handoff = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&missing_decision).expect("handoff json"),
    )
    .expect("missing decision handoff remains valid and explicit");
    assert_eq!(handoff.required_decisions[0].id, "human-review");
    assert!(handoff.blockers[0].contains("missing decision"));

    let mut no_blockers = agent_handoff_value("blocked");
    no_blockers["blockers"] = json!([]);
    let blocked_error = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&no_blockers).expect("handoff json"),
    )
    .expect_err("blocked handoff requires blockers");
    assert!(blocked_error.to_string().contains("must list blockers"));

    let mut unsafe_next = agent_handoff_value("ready");
    unsafe_next["nextSafeAction"] = json!("execute automatically and auto-merge the result");
    let unsafe_error = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&unsafe_next).expect("handoff json"),
    )
    .expect_err("unsafe next action rejected");
    assert!(unsafe_error.to_string().contains("unsafe action"));

    let mut executing_command = agent_handoff_value("ready");
    executing_command["allowedCommands"][0]["boundary"] = json!("runs immediately");
    let command_error = AgentHandoffContract::from_json_str(
        &serde_json::to_string_pretty(&executing_command).expect("handoff json"),
    )
    .expect_err("allowed command must be inert");
    assert!(command_error
        .to_string()
        .contains("must state commands are inert"));
}

#[test]
fn agent_handoff_generation_writes_advisory_contract_and_ledger_summary() {
    let root = unique_temp_dir("agent-handoff-generation");
    write_loop_dry_run_project(&root);
    let plan_path = write_loop_dry_run_plan(&root, "loop_project");
    let baseline_path = root.join("runs/baseline/run.json");
    fs::create_dir_all(baseline_path.parent().expect("baseline parent")).expect("baseline dir");
    fs::write(&baseline_path, "{}\n").expect("baseline artifact");
    let handoff_path = root.join("runs/agent-handoffs/temp-loop/handoff.json");

    let handoff =
        write_agent_handoff_contract_from_path(&plan_path, &handoff_path).expect("handoff writes");

    assert_eq!(
        handoff.schema_version,
        AGENT_HANDOFF_CONTRACT_SCHEMA_VERSION
    );
    assert_eq!(handoff.status, AgentHandoffStatus::Ready);
    assert_eq!(
        handoff.current_step.as_ref().expect("current step").step_id,
        "compare-runs"
    );
    assert!(handoff_path.is_file(), "handoff is generated local JSON");
    assert!(handoff
        .allowed_commands
        .iter()
        .all(|command| command.boundary.contains("inert")
            || command.boundary.contains("does not execute")));
    assert!(handoff
        .evidence_refs
        .iter()
        .any(|reference| reference.id == "loop-evidence-bundle"));
    assert!(
        root.join("runs/authoring-loop-ledgers/temp-loop/ledger.jsonl")
            .is_file(),
        "handoff generation records a journal/ledger summary"
    );
    let listed = list_agent_handoff_contracts(root.join("runs")).expect("handoffs list");
    assert_eq!(listed.len(), 1);
    assert_eq!(listed[0].loop_id, "temp-loop");
    let bundle = build_authoring_loop_evidence_bundle(
        &read_loop_plan_from_path(&plan_path),
        &root,
        &plan_path,
    )
    .expect("bundle read-model builds");
    let cockpit = build_studio_loop_cockpit_read_model(&[bundle], &listed, &[]);
    assert_eq!(cockpit.schema_version, STUDIO_LOOP_COCKPIT_SCHEMA_VERSION);
    assert_eq!(cockpit.loops.len(), 1);
    assert_eq!(cockpit.loops[0].loop_id, "temp-loop");
    assert_eq!(
        cockpit.loops[0]
            .current_step
            .as_ref()
            .expect("current step")
            .step_id,
        "compare-runs"
    );
    assert_eq!(cockpit.loops[0].handoff_status.as_deref(), Some("ready"));
    assert_eq!(cockpit.loops[0].bundle_status.as_deref(), Some("partial"));
    assert!(cockpit.loops[0]
        .allowed_commands
        .iter()
        .all(|command| command.boundary.contains("inert")
            || command.boundary.contains("does not execute")));
    assert!(cockpit.boundary.contains("does not execute commands"));
    assert!(
        !root
            .join("runs/authoring-loop-bundles/temp-loop/bundle.json")
            .exists(),
        "handoff generation reads bundle state in memory but does not create bundle artifacts"
    );

    fs::remove_dir_all(root).ok();
}

#[test]
fn agent_handoff_generation_rejects_non_generated_output_paths() {
    let root = unique_temp_dir("agent-handoff-output-policy");
    write_loop_dry_run_project(&root);
    let plan_path = write_loop_dry_run_plan(&root, "loop_project");
    let baseline_path = root.join("runs/baseline/run.json");
    fs::create_dir_all(baseline_path.parent().expect("baseline parent")).expect("baseline dir");
    fs::write(&baseline_path, "{}\n").expect("baseline artifact");

    let source_like_path = root.join("source/handoff.json");
    let rejected = write_agent_handoff_contract_from_path(&plan_path, &source_like_path)
        .expect_err("source-like handoff output path is rejected");

    assert!(rejected.to_string().contains("configured generated roots"));
    assert!(
        !source_like_path.exists(),
        "rejected handoff output must not be written"
    );

    let generated_path = root.join("runs/agent-handoffs/temp-loop/handoff.json");
    write_agent_handoff_contract_from_path(&plan_path, &generated_path)
        .expect("generated-root handoff output path writes");
    assert!(generated_path.is_file());

    fs::remove_dir_all(root).ok();
}

#[test]
fn handoff_output_path_relativizes_absolute_outputs_under_base() {
    let root = unique_temp_dir("handoff-output-relativize");
    let target_rel = Path::new("runs/agent-handoffs/temp-loop/handoff.json");
    fs::create_dir_all(root.join(target_rel.parent().expect("parent"))).expect("dirs");

    // An absolute output inside the (canonicalized) base is relativized to the
    // base-relative form even across symlinked temp prefixes, so the
    // generated-root policy accepts it regardless of relative/absolute
    // spelling. Previously a plain strip_prefix left it absolute and rejected.
    let absolute_output = root.join(target_rel);
    assert_eq!(
        relative_generated_output_path(&root, &absolute_output),
        target_rel
    );
    // A relative output is returned unchanged.
    assert_eq!(
        relative_generated_output_path(&root, target_rel),
        target_rel
    );

    fs::remove_dir_all(root).ok();
}

