#[test]
fn adversarial_input_fuzzing_plan_rejects_unsafe_output_and_missing_cleanup() {
    let unsafe_output = AdversarialInputFuzzingPlanArtifact::from_json_str(
            &json!({
                "schemaVersion": "adversarial-input-fuzzing-plan-v1",
                "planId": "qa14_3_unsafe_output",
                "runId": "run_fuzzing_plan_smoke",
                "inputDomain": {
                    "domainId": "movement-buttons",
                    "scenarioId": "collect-and-exit",
                    "scenarioCandidateRef": "evidence/scenarios/collect-and-exit/scenario-candidate.json",
                    "allowedKeys": ["left", "right"]
                },
                "deterministicSeed": 7,
                "budget": { "maxSteps": 8, "maxRuns": 1, "maxDurationMs": 2000, "maxArtifacts": 4, "maxOutputBytes": 65536 },
                "actionSet": ["press_key", "release_key"],
                "constraints": [{ "constraintId": "bounded-local-only", "description": "Use deterministic local evidence only." }],
                "stopCondition": { "conditionId": "budget-only", "description": "Stop at the declared budget." },
                "expectedEvidence": [{ "evidenceId": "seeded-inputs", "artifactKind": "fuzz_input", "pathHint": "evidence/fuzz/qa14_3_unsafe_output/fuzz-inputs.json" }],
                "outputRoot": "evidence/qa-workers/worker-1/fuzz/",
                "cleanupPolicy": { "mode": "retain_on_failure" },
                "status": "planned"
            })
            .to_string(),
        )
        .expect_err("output outside fuzz root rejected");
    assert!(unsafe_output.to_string().contains("outputRoot"));

    let missing_cleanup = AdversarialInputFuzzingPlanArtifact::from_json_str(
            &json!({
                "schemaVersion": "adversarial-input-fuzzing-plan-v1",
                "planId": "qa14_3_missing_cleanup",
                "runId": "run_fuzzing_plan_smoke",
                "inputDomain": {
                    "domainId": "movement-buttons",
                    "scenarioId": "collect-and-exit",
                    "scenarioCandidateRef": "evidence/scenarios/collect-and-exit/scenario-candidate.json",
                    "allowedKeys": ["left", "right"]
                },
                "deterministicSeed": 7,
                "budget": { "maxSteps": 8, "maxRuns": 1, "maxDurationMs": 2000, "maxArtifacts": 4, "maxOutputBytes": 65536 },
                "actionSet": ["press_key", "release_key"],
                "constraints": [{ "constraintId": "bounded-local-only", "description": "Use deterministic local evidence only." }],
                "stopCondition": { "conditionId": "budget-only", "description": "Stop at the declared budget." },
                "expectedEvidence": [{ "evidenceId": "seeded-inputs", "artifactKind": "fuzz_input", "pathHint": "evidence/fuzz/qa14_3_missing_cleanup/fuzz-inputs.json" }],
                "outputRoot": "evidence/fuzz/qa14_3_missing_cleanup/",
                "status": "planned"
            })
            .to_string(),
        )
        .expect_err("cleanup policy is required");
    assert!(!missing_cleanup.to_string().is_empty());
}

#[test]
fn qa_agent_work_queue_v1_accepts_fixture_states_and_boundaries() {
    for (fixture, expected_status) in [
        (
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.valid.fixture.json",
            QaAgentQueueStatus::Pass,
        ),
        (
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.failed.fixture.json",
            QaAgentQueueStatus::Fail,
        ),
        (
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.deferred.fixture.json",
            QaAgentQueueStatus::Deferred,
        ),
        (
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.flaky.fixture.json",
            QaAgentQueueStatus::Flaky,
        ),
        (
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.blocked.fixture.json",
            QaAgentQueueStatus::Blocked,
        ),
        (
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.stale.fixture.json",
            QaAgentQueueStatus::NeedsRerun,
        ),
    ] {
        let queue = QaAgentWorkQueueArtifact::from_json_str(&read_json_fixture(fixture))
            .unwrap_or_else(|error| panic!("{fixture} validates: {error:#}"));
        assert_eq!(queue.schema_version, QA_AGENT_WORK_QUEUE_SCHEMA_VERSION);
        assert_eq!(queue.items.len(), 1);
        let item = &queue.items[0];
        assert_eq!(item.status, expected_status);
        assert_eq!(item.assigned_role, "qa-agent");
        assert!(!item.expected_evidence.is_empty());
        assert!(item
            .scenario_target
            .scenario_pack_ref
            .path
            .contains("scenario"));
        assert!(item.task_ref.path.contains("production-task-board"));
        assert!(item.work_package_ref.path.contains("agent-work-package"));
        assert!(item.run_command_context.boundary.contains("Inert"));
        assert!(queue.generated_state.tracked_fixture_only);
        assert!(queue
            .generated_state
            .roots
            .iter()
            .any(|root| root == "runs/multi-agent-pipeline"));
        assert!(queue.boundary.contains("does not execute commands"));
        assert!(queue.boundary.contains("does not spawn agents"));
        assert!(queue.boundary.contains("does not mutate trusted files"));
        assert!(queue
            .boundary
            .contains("does not write trusted browser state"));
        assert!(queue.boundary.contains("does not auto-apply"));
        assert!(queue.boundary.contains("does not auto-merge"));
        assert!(queue.boundary.contains("does not self-approve"));
        assert!(queue
            .forbidden_actions
            .iter()
            .any(|action| action == "hidden background agents"));
        assert!(queue
            .forbidden_actions
            .iter()
            .any(|action| action == "unbounded spawning"));
        assert!(queue
            .forbidden_actions
            .iter()
            .any(|action| action == "browser command bridge"));
        assert!(queue
            .forbidden_actions
            .iter()
            .any(|action| action == "trusted browser writes"));
    }
}

#[test]
fn qa_agent_work_queue_v1_rejects_malformed_state_and_boundary_drift() {
    let malformed = QaAgentWorkQueueArtifact::from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.malformed.fixture.json",
    ))
    .expect_err("malformed QA queue fixture rejects");
    assert!(format!("{malformed:#}").contains("scenarioTarget"));

    let mut invalid_pass: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.valid.fixture.json",
    ))
    .expect("queue json");
    invalid_pass["items"][0]["blockedReasons"] = json!(["hidden blocker"]);
    let pass_error = QaAgentWorkQueueArtifact::from_json_str(&invalid_pass.to_string())
        .expect_err("pass item with blockers rejects");
    assert!(format!("{pass_error:#}").contains("pass qa agent work queue item"));

    let mut unsafe_command = invalid_pass.clone();
    unsafe_command["items"][0]["blockedReasons"] = json!([]);
    unsafe_command["items"][0]["runCommandContext"]["command"] =
        json!("cargo run -p ouroforge-cli -- mutation apply unsafe");
    let command_error = QaAgentWorkQueueArtifact::from_json_str(&unsafe_command.to_string())
        .expect_err("mutation command context rejects");
    assert!(format!("{command_error:#}").contains("must not request mutation"));

    let mut unsafe_boundary: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.valid.fixture.json",
    ))
    .expect("queue json");
    unsafe_boundary["boundary"] = json!("QA queue can run commands and write browser state.");
    let boundary_error = QaAgentWorkQueueArtifact::from_json_str(&unsafe_boundary.to_string())
        .expect_err("unsafe QA queue boundary rejects");
    assert!(format!("{boundary_error:#}").contains("does not execute commands"));
}

#[test]
fn qa_agent_work_queue_v1_rejects_validation_drift_and_mutation_attempts() {
    let valid = || -> serde_json::Value {
        serde_json::from_str(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.valid.fixture.json",
        ))
        .expect("queue json")
    };

    let mut generated_scenario_target = valid();
    generated_scenario_target["items"][0]["scenarioTarget"]["scenarioPackRef"]["path"] =
        json!("runs/multi-agent-pipeline/generated.scenarios.json");
    let scenario_error =
        QaAgentWorkQueueArtifact::from_json_str(&generated_scenario_target.to_string())
            .expect_err("generated scenario target rejects");
    assert!(format!("{scenario_error:#}").contains("scenarioPackRef"));

    let mut missing_evaluator_expectation = valid();
    missing_evaluator_expectation["items"][0]["expectedEvidence"] = json!([
        {
            "id": "scenario-result",
            "path": "runs/multi-agent-pipeline/demo/qa/scenario-result.json",
            "description": "expected scenario result"
        }
    ]);
    let expectation_error =
        QaAgentWorkQueueArtifact::from_json_str(&missing_evaluator_expectation.to_string())
            .expect_err("missing evaluator expectation rejects");
    assert!(format!("{expectation_error:#}").contains("expectedEvidence"));

    let mut unsafe_run_evidence = valid();
    unsafe_run_evidence["items"][0]["runEvidenceRefs"][0]["path"] =
        json!("examples/multi-agent-pipeline-v1/generated-run.json");
    let run_ref_error = QaAgentWorkQueueArtifact::from_json_str(&unsafe_run_evidence.to_string())
        .expect_err("run evidence outside generated roots rejects");
    assert!(format!("{run_ref_error:#}").contains("runEvidenceRefs"));

    let mut mutation_command = valid();
    mutation_command["items"][0]["runCommandContext"]["command"] =
        json!("gh pr merge 123 --squash --delete-branch");
    mutation_command["items"][0]["runCommandContext"]["argv"] =
        json!(["gh", "pr", "merge", "123", "--squash", "--delete-branch"]);
    let mutation_error = QaAgentWorkQueueArtifact::from_json_str(&mutation_command.to_string())
        .expect_err("merge command context rejects");
    assert!(format!("{mutation_error:#}").contains("runCommandContext"));

    let mut stale_duplicate = serde_json::from_str::<serde_json::Value>(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.stale.fixture.json",
    ))
    .expect("stale queue json");
    stale_duplicate["items"][0]["staleRunRefs"] =
        json!(["runs/multi-agent-pipeline/demo/qa/scenario-result.json"]);
    let stale_error = QaAgentWorkQueueArtifact::from_json_str(&stale_duplicate.to_string())
        .expect_err("stale refs cannot duplicate current evidence");
    assert!(format!("{stale_error:#}").contains("staleRunRefs"));

    let mut wrong_rerun_classification =
        serde_json::from_str::<serde_json::Value>(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/qa-agent-work-queue.stale.fixture.json",
        ))
        .expect("stale queue json");
    wrong_rerun_classification["items"][0]["failureClassification"] = json!("runtime-error");
    let rerun_error =
        QaAgentWorkQueueArtifact::from_json_str(&wrong_rerun_classification.to_string())
            .expect_err("needs-rerun classification rejects");
    assert!(format!("{rerun_error:#}").contains("stale-run-ref"));
}

#[test]
fn qa_agent_work_queue_v1_validates_status_transition_shape() {
    let mut valid_transition = serde_json::from_str::<serde_json::Value>(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.failed.fixture.json",
    ))
    .expect("failed queue json");
    valid_transition["items"][0]["statusTransition"] =
        json!({ "from": "needs-rerun", "to": "fail" });
    QaAgentWorkQueueArtifact::from_json_str(&valid_transition.to_string())
        .expect("needs-rerun to fail transition is valid");

    let mut invalid_transition = valid_transition.clone();
    invalid_transition["items"][0]["statusTransition"] = json!({ "from": "pass", "to": "fail" });
    let transition_error = QaAgentWorkQueueArtifact::from_json_str(&invalid_transition.to_string())
        .expect_err("pass to fail transition rejects");
    assert!(format!("{transition_error:#}").contains("invalid status transition"));

    let mut mismatched_transition = valid_transition;
    mismatched_transition["items"][0]["statusTransition"] =
        json!({ "from": "needs-rerun", "to": "pass" });
    let mismatch_error =
        QaAgentWorkQueueArtifact::from_json_str(&mismatched_transition.to_string())
            .expect_err("transition target must match status");
    assert!(format!("{mismatch_error:#}").contains("must match status"));
}

#[test]
fn qa_agent_work_queue_dashboard_links_scenario_run_evaluator_and_review_refs() {
    let (missing_root, missing_artifacts) =
        create_test_run("qa-agent-work-queue-dashboard-missing");
    let missing = read_dashboard_run(&missing_artifacts.run_dir).expect("dashboard reads");
    assert!(!missing.qa_agent_work_queues.present);
    assert_eq!(missing.qa_agent_work_queues.status, "missing");
    fs::remove_dir_all(missing_root).expect("missing fixture removed");

    let (root, artifacts) = create_test_run("qa-agent-work-queue-dashboard-present");
    let queue = QaAgentWorkQueueArtifact::from_json_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.valid.fixture.json",
    ))
    .expect("queue fixture validates");
    let path = "evidence/qa-agent-work-queue/queue.json";
    fs::create_dir_all(artifacts.run_dir.join("evidence/qa-agent-work-queue"))
        .expect("qa queue evidence dir exists");
    write_json(&artifacts.run_dir.join(path), &json!(queue)).expect("queue writes");
    add_evidence_artifact(
        &artifacts.run_dir,
        "qa-agent-work-queue",
        "application/json",
        path,
        json!({ "artifact": "qa_agent_work_queue" }),
    )
    .expect("queue indexed");
    let dashboard = read_dashboard_run(&artifacts.run_dir).expect("dashboard reads");
    assert!(dashboard.qa_agent_work_queues.present);
    assert_eq!(dashboard.qa_agent_work_queues.status, "passed");
    assert_eq!(dashboard.qa_agent_work_queues.queue_count, 1);
    assert_eq!(dashboard.qa_agent_work_queues.item_count, 1);
    assert_eq!(dashboard.qa_agent_work_queues.passed_count, 1);
    assert_eq!(dashboard.qa_agent_work_queues.evidence_refs[0], path);
    for expected_ref in [
        "examples/scenario-packs/project-smoke.scenarios.json",
        "examples/multi-agent-pipeline-v1/production-task-board.fixture.json",
        "examples/multi-agent-pipeline-v1/agent-work-package.valid.fixture.json",
        "examples/multi-agent-pipeline-v1/review-critic-gate.valid.fixture.json",
        "runs/multi-agent-pipeline/demo/qa/scenario-result.json",
        "runs/multi-agent-pipeline/demo/qa/evaluator-summary.json",
    ] {
        assert!(
            dashboard
                .qa_agent_work_queues
                .evidence_refs
                .iter()
                .any(|reference| reference == expected_ref),
            "missing linked QA queue ref {expected_ref}"
        );
    }
    assert!(dashboard
        .qa_agent_work_queues
        .boundary
        .contains("Read-only QA agent work queues"));
    fs::remove_dir_all(root).expect("fixture removed");

    let (malformed_root, malformed_artifacts) =
        create_test_run("qa-agent-work-queue-dashboard-malformed");
    let malformed_path = "evidence/qa-agent-work-queue/queue-malformed.json";
    fs::create_dir_all(
        malformed_artifacts
            .run_dir
            .join("evidence/qa-agent-work-queue"),
    )
    .expect("qa queue evidence dir exists");
    fs::write(
        malformed_artifacts.run_dir.join(malformed_path),
        "{not-json",
    )
    .expect("malformed queue writes");
    add_evidence_artifact(
        &malformed_artifacts.run_dir,
        "qa-agent-work-queue-malformed",
        "application/json",
        malformed_path,
        json!({ "artifact": "qa_agent_work_queue" }),
    )
    .expect("malformed queue indexed");
    let malformed = read_dashboard_run(&malformed_artifacts.run_dir).expect("dashboard reads");
    assert!(malformed.qa_agent_work_queues.present);
    assert_eq!(malformed.qa_agent_work_queues.status, "malformed");
    assert_eq!(malformed.qa_agent_work_queues.malformed_count, 1);
    fs::remove_dir_all(malformed_root).expect("malformed fixture removed");
}

#[test]
fn qa_agent_work_queue_is_studio_inspection_compatible() {
    let queue: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.valid.fixture.json",
    ))
    .expect("queue json");
    let model = studio_multi_agent_pipeline_inspection_read_model_from_json_str(
        &json!({ "qaAgentWorkQueue": queue }).to_string(),
    );
    let qa_section = model
        .sections
        .iter()
        .find(|section| section.id == "qa-queue")
        .expect("qa queue section");
    assert_eq!(qa_section.status, "present");
    assert_eq!(qa_section.item_count, 1);
    assert!(qa_section.blockers.is_empty());

    let stale: serde_json::Value = serde_json::from_str(&read_json_fixture(
        "examples/multi-agent-pipeline-v1/qa-agent-work-queue.stale.fixture.json",
    ))
    .expect("stale queue json");
    let blocked = studio_multi_agent_pipeline_inspection_read_model_from_json_str(
        &json!({ "qaAgentWorkQueues": [stale] }).to_string(),
    );
    let blocked_qa = blocked
        .sections
        .iter()
        .find(|section| section.id == "qa-queue")
        .expect("qa queue section");
    assert_eq!(blocked_qa.status, "blocked");
    assert!(blocked_qa
        .blockers
        .iter()
        .any(|blocker| blocker.contains("stale run ref")));

    let malformed = studio_multi_agent_pipeline_inspection_read_model_from_json_str(
        &json!({ "qaAgentWorkQueue": { "queueId": "malformed" } }).to_string(),
    );
    assert_eq!(malformed.status, "malformed");
    let malformed_qa = malformed
        .sections
        .iter()
        .find(|section| section.id == "qa-queue")
        .expect("qa queue section");
    assert_eq!(malformed_qa.status, "malformed");
    assert!(malformed_qa
        .malformed_reasons
        .iter()
        .any(|reason| reason.contains("qa-agent-work-queue")));
}

#[test]
fn qa_agent_work_queue_doc_audits_generated_state_and_governance() {
    let doc = read_repo_text("docs/qa-agent-work-queue-v1.md");
    for required in [
        "schemaVersion: qa-agent-work-queue-v1",
        "pass",
        "fail",
        "deferred",
        "blocked",
        "flaky",
        "needs-rerun",
        "does not execute commands",
        "does not spawn agents",
        "does not mutate trusted files",
        "does not write trusted browser state",
        "auto-apply",
        "auto-merge",
        "self-approve",
        "reviewer bypass",
        "Generated",
        "MAP13.9.1",
        "MAP13.9.2",
        "MAP13.9.3",
        "Issues #1 and #23 must remain open",
    ] {
        assert!(doc.contains(required), "QA queue doc missing {required}");
    }
    for forbidden in [
        "autonomously complete arbitrary games",
        "production-ready game engine",
        "replace Godot",
        "browser command bridge controls are allowed",
        "self approval is allowed",
    ] {
        assert!(
            !doc.to_ascii_lowercase()
                .contains(&forbidden.to_ascii_lowercase()),
            "doc must not contain forbidden claim: {forbidden}"
        );
    }
}

