#[test]
fn compares_runs_without_mutating_sources() {
    let (before_root, before) = create_test_run("ouroforge-compare-before-test");
    write_scenario_result_fixture(&before.run_dir, "passed");
    evaluate_run(&before.run_dir).expect("before verdict");
    let before_run_json =
        fs::read_to_string(before.run_dir.join("run.json")).expect("before run reads");
    let output_dir = before_root.join("comparisons");

    let artifact_path =
        write_run_comparison_artifact(&before.run_dir, &before.run_dir, &output_dir)
            .expect("comparison written");

    assert!(artifact_path.is_file());
    let comparison = read_json_value(&artifact_path).expect("comparison reads");
    assert_eq!(comparison["classification"], "no_change");
    assert_eq!(
        comparison["semantic"]["schemaVersion"],
        "run-semantic-diff-v1"
    );
    assert_eq!(
        comparison["semantic"]["reasons"][0]["summary"],
        "comparison classification is no_change"
    );
    assert_eq!(comparison["before"]["verdict_status"], "passed");
    assert_eq!(comparison["after"]["verdict_status"], "passed");
    assert_eq!(
        fs::read_to_string(before.run_dir.join("run.json")).expect("before run rereads"),
        before_run_json
    );
    fs::remove_dir_all(before_root).ok();
}

#[test]
fn compares_same_project_metadata_without_project_change() {
    let (root, run) = create_test_run("ouroforge-compare-project-same-test");
    write_scenario_result_fixture(&run.run_dir, "passed");
    evaluate_run(&run.run_dir).expect("verdict");
    write_project_metadata_fixture(
        &run.run_dir,
        project_metadata_fixture("minimal_2d", "manifesthash", "scenehash", Some("smoke")),
    );

    let comparison = compare_runs(&run.run_dir, &run.run_dir).expect("comparison");

    assert_eq!(comparison.semantic.project.relation, "same_project");
    assert!(!comparison.semantic.project.changed);
    assert!(comparison.semantic.project.changes.is_empty());
    assert_eq!(
        comparison
            .semantic
            .project
            .before
            .as_ref()
            .expect("project before")
            .id,
        "minimal_2d"
    );
    assert_eq!(
        comparison
            .semantic
            .project
            .after
            .as_ref()
            .expect("project after")
            .scenario_pack
            .as_ref()
            .expect("scenario pack")
            .id,
        "smoke"
    );

    fs::remove_dir_all(root).ok();
}

#[test]
fn compare_runs_summarizes_input_replay_artifact_changes() {
    let (before_root, before) = create_test_run("ouroforge-compare-replay-before-test");
    let (after_root, after) = create_test_run("ouroforge-compare-replay-after-test");
    write_scenario_result_fixture(&before.run_dir, "passed");
    write_scenario_result_fixture(&after.run_dir, "passed");
    evaluate_run(&before.run_dir).expect("before verdict");
    evaluate_run(&after.run_dir).expect("after verdict");
    write_scenario_input_replay_fixture(&after.run_dir, "bootstrap-smoke", 2);

    let comparison = compare_runs(&before.run_dir, &after.run_dir).expect("comparison");

    assert_eq!(comparison.before.input_replay_artifacts, 0);
    assert_eq!(comparison.after.input_replay_artifacts, 1);
    assert_eq!(comparison.deltas["input_replay_artifacts"], 1);
    assert_eq!(comparison.semantic.input_replay.before_count, 0);
    assert_eq!(comparison.semantic.input_replay.after_count, 1);
    assert_eq!(comparison.semantic.input_replay.added.len(), 1);
    assert!(comparison
        .semantic
        .reasons
        .iter()
        .any(|reason| reason.kind == "input_replay" && reason.severity == "changed"));

    fs::remove_dir_all(before_root).ok();
    fs::remove_dir_all(after_root).ok();
}

