#[test]
fn evaluates_scenario_assertions_against_captured_state() {
    let scenario = Scenario {
        id: "probe-smoke".to_string(),
        description: "probe".to_string(),
        steps: Vec::new(),
        assertions: vec![
            ScenarioAssertion::WorldState {
                world_state: json_path_equals("tick", json!(2)),
            },
            ScenarioAssertion::FrameStats {
                frame_stats: json_path_equals("fixedDeltaMs", json!(16)),
            },
            ScenarioAssertion::WorldState {
                world_state: json_path_equals("object.id", json!("missing")),
            },
            ScenarioAssertion::WorldState {
                world_state: json_path_equals("collisions.0.pairId", json!("goal:player")),
            },
            ScenarioAssertion::WorldState {
                world_state: json_path_assertion("collisions", |assertion| {
                    assertion.count_equals = Some(1);
                }),
            },
            ScenarioAssertion::RuntimeEvents {
                runtime_events: json_path_assertion("events", |assertion| {
                    assertion.count_greater_than = Some(0);
                }),
            },
            ScenarioAssertion::WorldFlags {
                world_flags: json_path_equals("coin_collected", json!(true)),
            },
            ScenarioAssertion::PhysicsEvidence {
                physics_evidence: json_path_equals("grounded.player", json!(true)),
            },
            ScenarioAssertion::ConsoleErrors {
                console_errors: json_path_assertion("logs", |assertion| {
                    assertion.count_equals = Some(0);
                }),
            },
            ScenarioAssertion::PerformanceMetrics {
                performance_metrics: json_path_assertion("ScriptDuration", |assertion| {
                    assertion.less_than = Some(json!(10));
                }),
            },
            ScenarioAssertion::CollisionEvidence {
                collision_evidence: json_path_equals(
                    "1.staticEntityId",
                    json!("tilemap.collision.authoring-map.terrain.2.0.wall"),
                ),
            },
            ScenarioAssertion::VfxEvidence {
                vfx_evidence: json_path_equals("0.emitterId", json!("run-dust")),
            },
            ScenarioAssertion::Scene3dCamera {
                scene3d_camera: json_path_equals("activeCameraId", json!("main-camera")),
            },
            ScenarioAssertion::Scene3dCamera {
                scene3d_camera: json_path_equals(
                    "activeCamera.projection.kind",
                    json!("perspective"),
                ),
            },
            ScenarioAssertion::Scene3dAnimation {
                scene3d_animation: json_path_equals("states.0.clipId", json!("cube-slide")),
            },
            ScenarioAssertion::Scene3dAnimation {
                scene3d_animation: json_path_equals("states.0.playing", json!(true)),
            },
        ],
    };
    let world_state = json!({
        "tick": 2,
        "object": { "id": "probe-square" },
        "collisions": [
            { "pairId": "goal:player" },
            { "pairId": "player:tilemap.collision.authoring-map.terrain.2.0.wall", "staticEntityId": "tilemap.collision.authoring-map.terrain.2.0.wall" }
        ],
        "physics": { "grounded": { "player": true } },
        "goalFlags": { "coin_collected": true }
    });
    let frame_stats = json!({ "fixedDeltaMs": 16 });
    let runtime_events = json!({ "stepCount": 0, "events": [{ "type": "runtime.physics.jump" }] });
    let performance_metrics = json!({ "ScriptDuration": 2.5 });
    let console_errors = json!({ "logs": [], "count": 0 });
    let vfx_events = json!([{ "emitterId": "run-dust" }]);
    let scene3d_camera = json!({
        "present": true,
        "activeCameraId": "main-camera",
        "activeCamera": {
            "projection": { "kind": "perspective", "fovDegrees": 60, "near": 1, "far": 1000 }
        },
        "cameraCount": 1
    });
    let scene3d_animation = json!({
        "present": true,
        "stateCount": 1,
        "activeStateCount": 1,
        "states": [{
            "clipId": "cube-slide",
            "targetNodeId": "cube",
            "currentFrame": 2,
            "playing": true
        }]
    });
    let none = serde_json::Value::Null;
    let sources = assertion_sources_for_test(
        &world_state,
        &frame_stats,
        &runtime_events,
        &world_state["goalFlags"],
        &world_state["physics"],
        &performance_metrics,
        &console_errors,
        &world_state["collisions"],
        &none,
        &none,
        &vfx_events,
        &scene3d_camera,
        &scene3d_animation,
        &none,
        &none,
        &none,
        &none,
    );

    let assertions = evaluate_scenario_assertions(&scenario, &sources);

    assert_eq!(assertions.len(), 16);
    assert_eq!(assertions[0]["passed"], true);
    assert_eq!(assertions[1]["passed"], true);
    assert_eq!(assertions[2]["passed"], false);
    assert_eq!(assertions[2]["actual"], "probe-square");
    assert_eq!(assertions[3]["passed"], true);
    assert_eq!(assertions[4]["operator"], "countEquals");
    assert_eq!(assertions[4]["evidence_ref"], "evidence/world-state.json");
    assert_eq!(assertions[5]["passed"], true);
    assert_eq!(assertions[6]["passed"], true);
    assert_eq!(assertions[6]["target"], "world_flags");
    assert_eq!(assertions[7]["passed"], true);
    assert_eq!(assertions[7]["target"], "physics_evidence");
    assert_eq!(assertions[8]["passed"], true);
    assert_eq!(assertions[9]["passed"], true);
    assert_eq!(assertions[10]["passed"], true);
    assert_eq!(assertions[10]["target"], "collision_evidence");
    assert_eq!(assertions[11]["passed"], true);
    assert_eq!(assertions[11]["target"], "vfx_evidence");
    assert_eq!(assertions[12]["passed"], true);
    assert_eq!(assertions[12]["target"], "scene3d_camera");
    assert_eq!(
        assertions[12]["evidence_ref"],
        "evidence/scene3d-camera.json"
    );
    assert_eq!(assertions[13]["passed"], true);
    assert_eq!(assertions[13]["actual"], "perspective");
    assert_eq!(assertions[14]["passed"], true);
    assert_eq!(assertions[14]["target"], "scene3d_animation");
    assert_eq!(
        assertions[14]["evidence_ref"],
        "evidence/scene3d-animation.json"
    );
    assert_eq!(assertions[15]["passed"], true);
    assert_eq!(assertions[15]["actual"], true);
}

#[test]
fn evaluates_bounded_scene3d_assertion_targets_against_probe_evidence() {
    let scenario = Scenario {
        id: "scene3d-assertion-smoke".to_string(),
        description: "bounded 3D assertion targets".to_string(),
        steps: Vec::new(),
        assertions: vec![
            ScenarioAssertion::Scene3dProbe {
                scene3d_probe: json_path_equals("status", json!("present")),
            },
            ScenarioAssertion::Scene3dTransform {
                scene3d_transform: json_path_equals("transforms.0.nodeId", json!("cube-node")),
            },
            ScenarioAssertion::Scene3dRender {
                scene3d_render: json_path_assertion("visibleObjectCount", |assertion| {
                    assertion.greater_than = Some(json!(0));
                }),
            },
            ScenarioAssertion::Scene3dCollision {
                scene3d_collision: json_path_equals("triggerCount", json!(1)),
            },
            ScenarioAssertion::Scene3dProbe {
                scene3d_probe: json_path_equals("nodeCount", json!(999)),
            },
        ],
    };
    let none = serde_json::Value::Null;
    let scene3d_probe = json!({
        "schemaVersion": "ouroforge.scene3d-runtime-probe.v1",
        "status": "present",
        "nodeCount": 2
    });
    let scene3d_transform = json!({
        "schemaVersion": "ouroforge.scene3d-transform-probe.v1",
        "transforms": [{
            "nodeId": "cube-node",
            "worldTransform": { "translation": { "x": 4, "y": 1, "z": 0 } }
        }]
    });
    let scene3d_render = json!({
        "schemaVersion": "ouroforge.scene3d-render-smoke.v1",
        "present": true,
        "visibleObjectCount": 1
    });
    let scene3d_collision = json!({
        "schemaVersion": "ouroforge.scene3d-collision-evidence.v1",
        "present": true,
        "triggerCount": 1
    });
    let sources = assertion_sources_for_test(
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &none,
        &scene3d_probe,
        &scene3d_transform,
        &scene3d_render,
        &scene3d_collision,
    );

    let assertions = evaluate_scenario_assertions(&scenario, &sources);

    assert_eq!(assertions.len(), 5);
    assert_eq!(assertions[0]["target"], "scene3d_probe");
    assert_eq!(assertions[0]["passed"], true);
    assert_eq!(assertions[1]["target"], "scene3d_transform");
    assert_eq!(
        assertions[1]["evidence_ref"],
        "evidence/scene3d-transforms.json"
    );
    assert_eq!(assertions[1]["passed"], true);
    assert_eq!(assertions[2]["target"], "scene3d_render");
    assert_eq!(assertions[2]["operator"], "greaterThan");
    assert_eq!(assertions[2]["passed"], true);
    assert_eq!(assertions[3]["target"], "scene3d_collision");
    assert_eq!(assertions[3]["passed"], true);
    assert_eq!(assertions[4]["target"], "scene3d_probe");
    assert_eq!(assertions[4]["passed"], false);
    assert_eq!(assertions[4]["actual"], 2);
}

