#[test]
fn mutation_review_rejects_proposal_id_that_does_not_match_patch_draft() {
    let (root, artifacts, proposal, _scene_path, _before_hash) =
        create_scene_only_mutation_fixture("review-gated-scene-apply-draft-link");
    let draft = write_scene_mutation_patch_draft(&artifacts.run_dir, &proposal);
    let other_proposal = create_mutation_proposal(
        &artifacts.run_dir,
        MutationProposalInput {
            reason: "second scene-only mutation fixture".to_string(),
            evidence_id: "scene-only-mutation-evidence".to_string(),
            target: proposal.target.clone(),
            path: proposal.path.clone(),
            from: proposal.from.clone(),
            to: "64".to_string(),
        },
    )
    .expect("second proposal created");

    let mismatch = append_mutation_review_decision(
        &artifacts.run_dir,
        MutationReviewDecisionInput {
            patch_draft_id: draft.drafts[0].id.clone(),
            proposal_id: Some(other_proposal.id.clone()),
            state: MutationReviewState::Accepted,
            reviewer_type: Some(MutationReviewReviewerType::Human),
            reason: "manual review attempts mismatched draft/proposal linkage".to_string(),
            evidence_refs: vec!["evidence/scene-only-mutation.json".to_string()],
            reviewer: "test-reviewer".to_string(),
            expected_hashes: None,
            guardrail_checklist: Some(Default::default()),

            source_patch_review: None,
        },
    )
    .expect_err("mismatched proposal/draft id rejected");
    assert!(mismatch.to_string().contains("does not match patch draft"));

    let review = read_mutation_review_artifact(&artifacts.run_dir).expect("review reads");
    assert!(review.decisions.is_empty());
    fs::remove_dir_all(root).ok();
}

#[test]
fn visual_edit_draft_review_preflight_requires_linked_accepted_decision() {
    let (root, artifacts, proposal, scene_path, _before_hash) =
        create_scene_only_mutation_fixture("visual-edit-review-preflight");
    let patch_draft = write_scene_mutation_patch_draft(&artifacts.run_dir, &proposal);
    let scene = read_scene(&scene_path).expect("scene reads");
    let mut visual_draft = valid_scene_visual_edit_draft_for_scene(&scene);

    let missing_gate =
        validate_visual_edit_draft_review_preflight(&artifacts.run_dir, &visual_draft)
            .expect_err("missing review gate rejects");
    assert!(missing_gate.to_string().contains("requires reviewGate"));

    let expected_hashes = MutationReviewExpectedHashes {
        proposal_index_hash: Some(
            canonical_json_digest(json!(read_mutation_proposals(&artifacts.run_dir).unwrap()))
                .unwrap(),
        ),
        patch_draft_hash: Some(
            canonical_json_digest(json!(read_patch_draft_artifact(&artifacts.run_dir).unwrap()))
                .unwrap(),
        ),
        evidence_index_hash: Some(
            canonical_json_digest(json!(read_evidence_index(&artifacts.run_dir).unwrap())).unwrap(),
        ),
    };
    let decision = accepted_scene_apply_decision(
        &artifacts.run_dir,
        &patch_draft,
        &proposal,
        Some(expected_hashes),
    );
    visual_draft.review_gate = Some(VisualEditDraftReviewGate {
        proposal_id: proposal.id.clone(),
        patch_draft_id: patch_draft.drafts[0].id.clone(),
        review_decision_id: decision.id.clone(),
    });

    let preflight = validate_visual_edit_draft_review_preflight(&artifacts.run_dir, &visual_draft)
        .expect("accepted linked decision passes preflight");
    assert_eq!(preflight.draft_id, visual_draft.draft_id);
    assert_eq!(preflight.proposal_id, proposal.id);
    assert_eq!(preflight.patch_draft_id, patch_draft.drafts[0].id);
    assert_eq!(preflight.review_decision_id, decision.id);
    assert_eq!(preflight.status, "review_preflight_passed");

    fs::remove_dir_all(root).ok();
}

#[test]
fn visual_edit_draft_review_preflight_rejects_rejected_mismatched_and_stale_decisions() {
    let (root, artifacts, proposal, scene_path, _before_hash) =
        create_scene_only_mutation_fixture("visual-edit-review-preflight-rejects");
    let patch_draft = write_scene_mutation_patch_draft(&artifacts.run_dir, &proposal);
    let scene = read_scene(&scene_path).expect("scene reads");
    let mut visual_draft = valid_scene_visual_edit_draft_for_scene(&scene);

    let rejected = append_mutation_review_decision(
        &artifacts.run_dir,
        MutationReviewDecisionInput {
            patch_draft_id: patch_draft.drafts[0].id.clone(),
            proposal_id: Some(proposal.id.clone()),
            state: MutationReviewState::Rejected,
            reviewer_type: Some(MutationReviewReviewerType::Human),
            reason: "manual review rejected visual edit draft".to_string(),
            evidence_refs: vec!["evidence/scene-only-mutation.json".to_string()],
            reviewer: "test-reviewer".to_string(),
            expected_hashes: None,
            guardrail_checklist: Some(Default::default()),

            source_patch_review: None,
        },
    )
    .expect("rejected decision appends");
    visual_draft.review_gate = Some(VisualEditDraftReviewGate {
        proposal_id: proposal.id.clone(),
        patch_draft_id: patch_draft.drafts[0].id.clone(),
        review_decision_id: rejected.id,
    });
    let rejected_error =
        validate_visual_edit_draft_review_preflight(&artifacts.run_dir, &visual_draft)
            .expect_err("rejected decision fails preflight");
    assert!(rejected_error
        .to_string()
        .contains("requires an accepted decision"));

    let stale = accepted_scene_apply_decision(
        &artifacts.run_dir,
        &patch_draft,
        &proposal,
        Some(MutationReviewExpectedHashes {
            proposal_index_hash: Some("stale-proposal-index".to_string()),
            patch_draft_hash: Some("stale-patch-draft".to_string()),
            evidence_index_hash: Some("stale-evidence-index".to_string()),
        }),
    );
    visual_draft.review_gate = Some(VisualEditDraftReviewGate {
        proposal_id: proposal.id.clone(),
        patch_draft_id: patch_draft.drafts[0].id.clone(),
        review_decision_id: stale.id,
    });
    let stale_error =
        validate_visual_edit_draft_review_preflight(&artifacts.run_dir, &visual_draft)
            .expect_err("stale expected hashes fail preflight");
    assert!(stale_error
        .to_string()
        .contains("proposal index hash mismatch"));

    let accepted = accepted_scene_apply_decision(
        &artifacts.run_dir,
        &patch_draft,
        &proposal,
        Some(MutationReviewExpectedHashes {
            proposal_index_hash: Some(
                canonical_json_digest(json!(read_mutation_proposals(&artifacts.run_dir).unwrap()))
                    .unwrap(),
            ),
            patch_draft_hash: Some(
                canonical_json_digest(
                    json!(read_patch_draft_artifact(&artifacts.run_dir).unwrap()),
                )
                .unwrap(),
            ),
            evidence_index_hash: Some(
                canonical_json_digest(json!(read_evidence_index(&artifacts.run_dir).unwrap()))
                    .unwrap(),
            ),
        }),
    );
    visual_draft.review_gate = Some(VisualEditDraftReviewGate {
        proposal_id: proposal.id.clone(),
        patch_draft_id: "missing-patch-draft".to_string(),
        review_decision_id: accepted.id,
    });
    let mismatch_error =
        validate_visual_edit_draft_review_preflight(&artifacts.run_dir, &visual_draft)
            .expect_err("mismatched patch draft linkage fails preflight");
    assert!(mismatch_error
        .to_string()
        .contains("patch draft id not found"));

    fs::remove_dir_all(root).ok();
}

#[test]
fn visual_edit_draft_application_records_review_gated_apply_lifecycle() {
    let (root, artifacts, proposal, scene_path, before_hash) =
        create_scene_only_mutation_fixture("visual-edit-draft-application");
    let patch_draft = write_scene_mutation_patch_draft(&artifacts.run_dir, &proposal);
    let scene = read_scene(&scene_path).expect("scene reads");
    let mut visual_draft = valid_scene_visual_edit_draft_for_scene(&scene);
    let decision = accepted_scene_apply_decision(
        &artifacts.run_dir,
        &patch_draft,
        &proposal,
        Some(current_mutation_review_expected_hashes(&artifacts.run_dir)),
    );
    visual_draft.review_gate = Some(VisualEditDraftReviewGate {
        proposal_id: proposal.id.clone(),
        patch_draft_id: patch_draft.drafts[0].id.clone(),
        review_decision_id: decision.id.clone(),
    });
    let transaction_output = root.join("transactions/visual-edit-apply.json");
    let operation = scene_apply_operation(
        &proposal,
        &scene_path,
        before_hash,
        Some(decision.id.clone()),
    );
    let transaction =
        apply_scene_only_mutation_operation(&artifacts.run_dir, &operation, &transaction_output)
            .expect("review-gated scene apply succeeds");
    let command_context = VisualEditDraftApplyCommandContext {
        schema_version: "visual-edit-draft-apply-command-context-v1".to_string(),
        command: "cargo run -p ouroforge-cli -- edit draft-apply draft.json".to_string(),
        argv: vec![
            "cargo".to_string(),
            "run".to_string(),
            "-p".to_string(),
            "ouroforge-cli".to_string(),
            "--".to_string(),
            "edit".to_string(),
            "draft-apply".to_string(),
            "draft.json".to_string(),
        ],
        draft_path: "draft.json".to_string(),
        project_path: "project".to_string(),
        run_dir: artifacts.run_dir.to_string_lossy().to_string(),
        transaction_output: transaction_output.to_string_lossy().to_string(),
        guardrail: "reproducible CLI context only; dashboards may display but must not execute it"
            .to_string(),
    };

    let application = append_visual_edit_draft_application(
        &artifacts.run_dir,
        &visual_draft,
        &transaction,
        &transaction_output,
        &scene_path,
        command_context.clone(),
    )
    .expect("visual edit application records");

    assert_eq!(application.draft_id, visual_draft.draft_id);
    assert_eq!(application.proposal_id, proposal.id);
    assert_eq!(application.patch_draft_id, patch_draft.drafts[0].id);
    assert_eq!(application.review_decision_id, decision.id);
    assert_eq!(application.transaction_id, transaction.id);
    assert_eq!(
        application.transaction_artifact_path,
        transaction_output.to_string_lossy()
    );
    assert_eq!(application.target_scene_path, scene_path.to_string_lossy());
    assert_eq!(application.before_scene_hash, transaction.before_scene_hash);
    assert_eq!(
        application.after_scene_hash,
        transaction.after_scene_hash.unwrap()
    );
    assert_eq!(application.rollback, transaction.rollback);
    assert_eq!(application.command_context, command_context);
    assert_eq!(application.status, "applied");

    let index = read_visual_edit_draft_applications(&artifacts.run_dir)
        .expect("visual edit application index reads");
    assert_eq!(index.applications, vec![application.clone()]);
    let lifecycle =
        read_dashboard_mutation_lifecycle(&artifacts.run_dir, std::slice::from_ref(&proposal));
    let visual_stage = lifecycle
        .stages
        .iter()
        .find(|stage| stage.id == "visual_draft_applied")
        .expect("visual draft application stage exported");
    assert_eq!(visual_stage.state, "applied");
    assert_eq!(visual_stage.record_count, 1);
    assert_eq!(
        visual_stage.artifact_path.as_deref(),
        Some("mutation/visual-edit-applications.json")
    );
    assert!(
        visual_stage
            .evidence_refs
            .contains(&"mutation/visual-edit-applications.json".to_string()),
        "visual draft lifecycle stage must preserve the generated application artifact ref"
    );
    let cockpit = dashboard_review_cockpit(&lifecycle, &[]);
    assert_eq!(cockpit.applications.id, "applications");
    assert_eq!(cockpit.applications.record_count, 2);
    assert!(cockpit
        .applications
        .record_ids
        .iter()
        .any(|id| id.starts_with("visual-edit-application-")));
    assert!(cockpit
        .applications
        .artifact_path
        .as_deref()
        .is_some_and(|path| path.contains("visual-edit-applications.json")));
    assert!(
        cockpit
            .applications
            .evidence_refs
            .contains(&"mutation/visual-edit-applications.json".to_string()),
        "review cockpit must carry visual draft application evidence refs forward"
    );
    let journal = update_journal(&artifacts.run_dir).expect("journal updates");
    assert!(journal.contains("### Visual Draft Applications"));
    assert!(journal.contains("Rerun context is inert/display-only"));
    assert!(journal.contains("cargo run -p ouroforge-cli -- edit draft-apply draft.json"));
    assert!(read_dashboard_run(&artifacts.run_dir)
        .expect("dashboard reads")
        .mutation_artifacts
        .iter()
        .any(|artifact| artifact.id == "mutation-visual-edit-applications"));
    let ledger = read_ledger_events(&artifacts.run_dir).expect("ledger reads");
    assert!(ledger
        .iter()
        .any(|event| { event["event"] == "visual_edit_draft.applied" }));
    fs::remove_dir_all(root).ok();
}

