#[test]
fn scene_trigger_flag_rules_v1_rejects_duplicate_and_unknown_flags() {
    let mut duplicate_flag: SceneDocument = serde_json::from_value(json!({
        "schemaVersion": "1",
        "id": "duplicate-trigger-flags",
        "bounds": { "width": 64, "height": 64 },
        "gameplayRules": {
            "version": "1",
            "flags": [
                { "id": "coin_collected" },
                { "id": "coin_collected" }
            ]
        },
        "entities": [
            {
                "id": "player",
                "sprite": { "color": "#5eead4" },
                "components": {
                    "transform": { "x": 0, "y": 0 },
                    "velocity": { "x": 0, "y": 0 },
                    "size": { "width": 16, "height": 16 },
                    "controllable": true
                }
            }
        ]
    }))
    .expect("duplicate flag scene parses");
    let duplicate_error =
        validate_scene(&duplicate_flag).expect_err("duplicate gameplay flag rejected");
    assert!(duplicate_error
        .to_string()
        .contains("duplicate scene gameplayRules flag id: coin_collected"));

    duplicate_flag
        .gameplay_rules
        .as_mut()
        .expect("gameplay rules")
        .flags
        .pop();
    duplicate_flag.entities[0].components.trigger = Some(SceneTrigger {
        id: "collect_coin".to_string(),
        kind: "overlap".to_string(),
        target_flag: Some("missing_flag".to_string()),
        required_flags: Vec::new(),
        on_enter: vec![SceneTriggerAction {
            kind: "setFlag".to_string(),
            flag: Some("coin_collected".to_string()),
            value: Some(true),
            entity_id: None,
        }],
    });
    let unknown_error = validate_scene(&duplicate_flag).expect_err("unknown trigger flag rejected");
    assert!(unknown_error
        .to_string()
        .contains("trigger targetFlag references unknown gameplayRules flag: missing_flag"));
}

#[test]
fn scene_component_model_v2_validates_hashes_and_bounded_edits() {
    let temp = unique_temp_dir("scene-component-model-v2-validation-edit");
    fs::create_dir_all(&temp).expect("temp dir exists");
    let scene_path = temp.join("scene-components-v2.json");
    fs::write(
        &scene_path,
        include_str!("../../../examples/game-runtime/scene-components-v2.json"),
    )
    .expect("fixture written");

    let scene = read_scene(&scene_path).expect("v2 fixture validates");
    let first_hash = hash_scene_document(&scene).expect("hash created");
    let round_trip: SceneDocument =
        serde_json::from_value(serde_json::to_value(&scene).unwrap()).expect("round trip parses");
    let second_hash = hash_scene_document(&round_trip).expect("hash repeats");
    assert_eq!(first_hash, second_hash);
    assert_eq!(first_hash.algorithm, "fnv1a64-canonical-json-v1");

    for path in [
        "components.status.hitPoints",
        "components.status.maxHitPoints",
        "components.input.moveSpeed",
        "components.input.jumpImpulse",
        "components.cameraTarget.weight",
        "components.uiText.text",
    ] {
        assert!(supported_scene_edit_paths().contains(&path));
    }

    edit_scene(
        &scene_path,
        SceneEdit {
            entity_id: "player".to_string(),
            path: "components.status.hitPoints".to_string(),
            value: json!(2),
        },
    )
    .expect("status edit applies");
    edit_scene(
        &scene_path,
        SceneEdit {
            entity_id: "player".to_string(),
            path: "components.input.moveSpeed".to_string(),
            value: json!(4),
        },
    )
    .expect("input edit applies");
    edit_scene(
        &scene_path,
        SceneEdit {
            entity_id: "player".to_string(),
            path: "components.cameraTarget.weight".to_string(),
            value: json!(3),
        },
    )
    .expect("camera target edit applies");
    let edited = edit_scene(
        &scene_path,
        SceneEdit {
            entity_id: "hud_coin".to_string(),
            path: "components.uiText.text".to_string(),
            value: json!("Coin: 1/1"),
        },
    )
    .expect("ui text edit applies");

    assert_eq!(
        edited.entities[0]
            .components
            .status
            .as_ref()
            .expect("status")
            .hit_points,
        Some(2)
    );
    assert_eq!(
        edited.entities[0]
            .components
            .input
            .as_ref()
            .expect("input")
            .move_speed,
        Some(4)
    );
    assert_eq!(
        edited.entities[0]
            .components
            .camera_target
            .as_ref()
            .expect("camera target")
            .weight,
        3
    );
    assert_eq!(
        edited.entities[2]
            .components
            .ui_text
            .as_ref()
            .expect("ui text")
            .text,
        "Coin: 1/1"
    );
    assert_ne!(
        first_hash,
        hash_scene_document(&edited).expect("edited hash created")
    );

    let missing_component = edit_scene(
        &scene_path,
        SceneEdit {
            entity_id: "coin".to_string(),
            path: "components.input.moveSpeed".to_string(),
            value: json!(2),
        },
    )
    .expect_err("missing optional component is not created by edit path");
    assert!(missing_component
        .to_string()
        .contains("requires input component"));

    fs::remove_dir_all(temp).ok();
}

