#[test]
fn regression_promotion_draft_schema_accepts_valid_evidence_linked_draft() {
    let draft = valid_regression_promotion_draft();
    draft.validate().expect("valid regression promotion draft");
    let value = serde_json::to_value(&draft).expect("draft serializes");
    assert_eq!(value["schemaVersion"], "regression-promotion-draft-v1");
    assert_eq!(value["sourceEvidence"]["scenarioId"], "failed-smoke");
    assert_eq!(value["target"]["scenarioPackId"], "regression");
    let parsed = RegressionPromotionDraft::from_json_str(
        &serde_json::to_string(&value).expect("draft to json"),
    )
    .expect("draft parses");
    assert_eq!(parsed, draft);
}

#[test]
fn regression_promotion_draft_schema_rejects_unsafe_or_malformed_links() {
    let mut bad_schema = valid_regression_promotion_draft();
    bad_schema.schema_version = "bad".to_string();
    assert!(bad_schema
        .validate()
        .expect_err("bad schema rejected")
        .to_string()
        .contains("schemaVersion"));

    let mut escaping_evidence = valid_regression_promotion_draft();
    escaping_evidence.source_evidence.evidence_refs[0] = "../secret.json".to_string();
    assert!(escaping_evidence
        .validate()
        .expect_err("escaping evidence rejected")
        .to_string()
        .contains("must not escape"));

    let mut duplicate_evidence = valid_regression_promotion_draft();
    duplicate_evidence.source_evidence.evidence_ids = vec!["same".to_string(), "same".to_string()];
    assert!(duplicate_evidence
        .validate()
        .expect_err("duplicate evidence id rejected")
        .to_string()
        .contains("duplicate regression promotion evidence id"));

    let mut hidden_target = valid_regression_promotion_draft();
    hidden_target.target.scenario_pack_path = ".omx/regression.json".to_string();
    assert!(hidden_target
        .validate()
        .expect_err("hidden target rejected")
        .to_string()
        .contains("hidden"));

    let mut mismatched_scenario = valid_regression_promotion_draft();
    mismatched_scenario.proposed_scenario.id = "other-scenario".to_string();
    assert!(mismatched_scenario
        .validate()
        .expect_err("mismatched scenario rejected")
        .to_string()
        .contains("must match sourceEvidence scenarioId"));

    // scenarioResultPath must anchor an actual scenario result, not just any
    // run-relative evidence/mutation/sandbox ref.
    let mut non_scenario_result = valid_regression_promotion_draft();
    non_scenario_result.source_evidence.scenario_result_path =
        "mutation/proposals.json".to_string();
    assert!(non_scenario_result
        .validate()
        .expect_err("non-scenario scenarioResultPath rejected")
        .to_string()
        .contains("must start with evidence/"));

    let mut sandbox_result = valid_regression_promotion_draft();
    sandbox_result.source_evidence.scenario_result_path =
        "sandbox/scenario-result-1.json".to_string();
    assert!(sandbox_result
        .validate()
        .expect_err("sandbox scenarioResultPath rejected")
        .to_string()
        .contains("must start with evidence/"));

    let mut non_result_filename = valid_regression_promotion_draft();
    non_result_filename.source_evidence.scenario_result_path =
        "evidence/scenarios/failed-smoke/after-run.json".to_string();
    assert!(non_result_filename
        .validate()
        .expect_err("non-result scenario filename rejected")
        .to_string()
        .contains("scenarioResultPath must reference a scenario result"));

    let mut contains_result_filename = valid_regression_promotion_draft();
    contains_result_filename
        .source_evidence
        .scenario_result_path =
        "evidence/scenarios/failed-smoke/not-scenario-result.json".to_string();
    assert!(contains_result_filename
        .validate()
        .expect_err("contains-result scenario filename rejected")
        .to_string()
        .contains("scenarioResultPath must reference a scenario result"));

    // projectManifestPath must be named ouroforge.project.json by file name,
    // not merely end with that string (a raw suffix check wrongly accepts
    // names like not-ouroforge.project.json that ProjectManifest::from_path
    // rejects).
    let mut suffix_manifest = valid_regression_promotion_draft();
    suffix_manifest.target.project_manifest_path = "configs/not-ouroforge.project.json".to_string();
    assert!(suffix_manifest
        .validate()
        .expect_err("suffix-only manifest filename rejected")
        .to_string()
        .contains("file name must be"));
}

#[test]
fn regression_promotion_selects_only_documented_scenario_result_filenames() {
    let (root, artifacts) = create_test_run("regression-promotion-scenario-result-filename");
    let run_dir = &artifacts.run_dir;
    fs::create_dir_all(run_dir.join("evidence/scenarios/failed-smoke"))
        .expect("scenario evidence dir");
    let bad_path = "evidence/scenarios/failed-smoke/not-scenario-result.json";
    fs::write(
        run_dir.join(bad_path),
        serde_json::to_string_pretty(&json!({
            "scenario_id": "failed-smoke",
            "status": "failed"
        }))
        .expect("scenario result serializes"),
    )
    .expect("bad scenario result fixture");
    add_evidence_artifact(
        run_dir,
        "bad-scenario-result",
        "application/json",
        bad_path,
        json!({ "artifact": "scenario_result", "scenario_id": "failed-smoke" }),
    )
    .expect("bad scenario result indexed");
    let evidence = read_evidence_index(run_dir).expect("evidence reads");
    let verdict = json!({
        "failures": [{
            "scenario_id": "failed-smoke",
            "path": bad_path
        }]
    });
    let rejected = select_failed_scenario_result_path(run_dir, &verdict, &evidence, "failed-smoke")
        .expect_err("non-document scenario-result filename rejected");
    assert!(rejected
        .to_string()
        .contains("could not find failed scenario result"));

    let valid_path = "evidence/scenarios/failed-smoke/scenario-result.json";
    fs::write(
        run_dir.join(valid_path),
        serde_json::to_string_pretty(&json!({
            "scenario_id": "failed-smoke",
            "status": "failed"
        }))
        .expect("scenario result serializes"),
    )
    .expect("valid scenario result fixture");
    add_evidence_artifact(
        run_dir,
        "metadata-scenario-result",
        "application/json",
        valid_path,
        json!({ "artifact": "scenario_result", "scenario_id": "failed-smoke" }),
    )
    .expect("valid scenario result indexed");
    let evidence = read_evidence_index(run_dir).expect("evidence rereads");
    let selected = select_failed_scenario_result_path(
        run_dir,
        &json!({ "failures": [] }),
        &evidence,
        "failed-smoke",
    )
    .expect("valid metadata scenario result selected");
    assert_eq!(selected, valid_path);

    let suffixed_path = "evidence/scenarios/failed-smoke/scenario-result-1.json";
    assert!(is_scenario_result_artifact_path(suffixed_path));

    fs::remove_dir_all(root).expect("fixture removed");
}

