#[test]
fn dashboard_read_model_lists_runs_and_categorizes_artifacts() {
    let (root, artifacts) = create_test_run("dashboard-read-model");
    fs::write(
        artifacts.run_dir.join("verdict.json"),
        "{\"status\":\"failed\",\"summary\":\"fixture failure\"}\n",
    )
    .expect("verdict written");
    fs::create_dir_all(artifacts.run_dir.join("evidence/workers/worker-1"))
        .expect("worker evidence dir");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/workers/worker-1/browser-smoke.png"),
        b"png fixture",
    )
    .expect("screenshot written");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/workers/worker-1/world-state.json"),
        "{\"object\":{\"x\":40}}\n",
    )
    .expect("world state written");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/workers/worker-1/console-log.json"),
        "[{\"level\":\"info\",\"text\":\"ready\"}]\n",
    )
    .expect("console log written");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/workers/worker-1/frame-stats.json"),
        "{\"frame\":3,\"fps\":60}\n",
    )
    .expect("frame stats written");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/workers/worker-1/performance-metrics.json"),
        "{\"metrics\":[{\"name\":\"ScriptDuration\",\"value\":1}]}\n",
    )
    .expect("performance metrics written");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/workers/worker-1/cdp-trace-summary.json"),
        "{\"bounded\":true,\"events\":[]}\n",
    )
    .expect("cdp trace summary written");
    fs::create_dir_all(artifacts.run_dir.join("evidence/scenarios/bootstrap-smoke"))
        .expect("scenario evidence dir");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/scenarios/bootstrap-smoke/scenario-result.json"),
        "{\"scenario_id\":\"bootstrap-smoke\",\"status\":\"passed\"}\n",
    )
    .expect("scenario result written");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-screenshot",
        "image/png",
        "evidence/workers/worker-1/browser-smoke.png",
        json!({ "worker_id": "worker-1" }),
    )
    .expect("screenshot indexed");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-world-state",
        "application/json",
        "evidence/workers/worker-1/world-state.json",
        json!({ "probe_call": "getWorldState", "worker_id": "worker-1" }),
    )
    .expect("world state indexed");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-console-log",
        "application/json",
        "evidence/workers/worker-1/console-log.json",
        json!({ "artifact": "console_log", "worker_id": "worker-1" }),
    )
    .expect("console log indexed");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-frame-stats",
        "application/json",
        "evidence/workers/worker-1/frame-stats.json",
        json!({ "probe_call": "getFrameStats", "worker_id": "worker-1" }),
    )
    .expect("frame stats indexed");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-performance-metrics",
        "application/json",
        "evidence/workers/worker-1/performance-metrics.json",
        json!({ "artifact": "performance_metrics", "worker_id": "worker-1" }),
    )
    .expect("performance metrics indexed");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-cdp-trace-summary",
        "application/json",
        "evidence/workers/worker-1/cdp-trace-summary.json",
        json!({ "artifact": "cdp_trace_summary", "worker_id": "worker-1" }),
    )
    .expect("cdp trace summary indexed");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-scenario-result",
        "application/json",
        "evidence/scenarios/bootstrap-smoke/scenario-result.json",
        json!({ "artifact": "scenario_result" }),
    )
    .expect("scenario result indexed");
    create_mutation_proposal(
        &artifacts.run_dir,
        MutationProposalInput {
            reason: "fixture failure".to_string(),
            evidence_id: "fixture-world-state".to_string(),
            target: "seeds/platformer.yaml".to_string(),
            path: "scenarios.bootstrap-smoke.assertions".to_string(),
            from: "x == -1".to_string(),
            to: "x == 40".to_string(),
        },
    )
    .expect("mutation proposal created");

    let runs = list_dashboard_runs(root.join("runs")).expect("dashboard runs listed");
    assert_eq!(runs.len(), 1);
    assert_eq!(runs[0].verdict_status, "failed");
    assert_eq!(runs[0].scenario_status, "pending");
    assert_eq!(runs[0].evidence_count, 7);
    assert_eq!(runs[0].mutation_count, 1);
    assert_eq!(runs[0].worker_count, 1);

    let model = read_dashboard_run(&artifacts.run_dir).expect("dashboard run read");
    assert_eq!(model.summary.id, runs[0].id);
    assert_eq!(model.evidence.len(), 7);
    assert_eq!(model.screenshots.len(), 1);
    assert_eq!(model.world_states.len(), 1);
    assert_eq!(model.console_logs.len(), 1);
    assert_eq!(model.frame_metrics.len(), 1);
    assert_eq!(model.performance_metrics.len(), 1);
    assert_eq!(model.cdp_trace_summaries.len(), 1);
    assert_eq!(model.scenario_results.len(), 1);
    assert_eq!(model.mutation_artifacts.len(), 1);
    assert_eq!(model.mutations.len(), 1);
    assert!(model.transaction_provenance.is_none());
    assert_eq!(model.evidence_fidelity.openchrome_cdp.status, "present");
    assert_eq!(model.evidence_fidelity.openchrome_cdp.observed_count, 4);
    assert_eq!(model.evidence_fidelity.command_context.status, "present");
    assert_eq!(model.evidence_fidelity.transaction.status, "missing");
    assert_eq!(model.evidence_fidelity.input_replay.status, "missing");
    assert_eq!(
        model.summary.evidence_fidelity.openchrome_cdp.status,
        model.evidence_fidelity.openchrome_cdp.status
    );
    let world_state = model.world_states[0]
        .value
        .as_ref()
        .expect("world state JSON loaded");
    let console_log = model.console_logs[0]
        .value
        .as_ref()
        .expect("console log JSON loaded");
    assert_eq!(world_state["object"]["x"], json!(40));
    assert_eq!(console_log[0]["text"], json!("ready"));
    assert!(model
        .evidence_categories
        .iter()
        .any(|category| category.id == "screenshots" && category.count == 1));
    assert!(model
        .evidence_categories
        .iter()
        .any(|category| { category.id == "frame_performance_metrics" && category.count == 2 }));
    assert!(model
        .evidence_categories
        .iter()
        .any(|category| { category.id == "console_cdp_summaries" && category.count == 2 }));
    assert!(model
        .evidence_categories
        .iter()
        .any(|category| category.id == "scenario_results" && category.count == 1));
    assert!(model
        .evidence_categories
        .iter()
        .any(|category| category.id == "mutation_artifacts" && category.count == 1));

    fs::remove_dir_all(root).expect("fixture removed");
}

#[test]
fn dashboard_plugin_registry_read_model_exposes_read_only_fixture_shape() {
    let (root, artifacts) = create_test_run("dashboard-plugin-registry");
    let plugin_fixture =
        read_json_fixture("examples/plugin-registry-evidence-v1/valid/plugin-registry.sample.json");
    let plugin_artifact =
        plugin_evidence::PluginRegistryEvidenceArtifact::from_json_str(&plugin_fixture)
            .expect("plugin registry fixture validates");
    plugin_evidence::write_plugin_registry_evidence(&artifacts.run_dir, &plugin_artifact)
        .expect("plugin evidence writes and indexes");

    let model = read_dashboard_run(&artifacts.run_dir).expect("dashboard run reads");
    assert!(model.plugin_registry.present);
    assert_eq!(model.plugin_registry.status, "blocked");
    assert_eq!(model.plugin_registry.registry_count, 1);
    assert_eq!(model.plugin_registry.plugin_count, 2);
    assert_eq!(model.plugin_registry.blocked_count, 1);
    assert_eq!(model.plugin_registry.malformed_count, 0);
    assert!(model
        .plugin_registry
        .boundary
        .contains("must not install, update, delete"));
    assert!(model.plugin_registry.boundary.contains("run commands"));
    assert!(model
        .plugin_registry
        .evidence_refs
        .contains(&"evidence/plugins/plugin-registry-fixture.json".to_string()));

    let registry = model
        .plugin_registry
        .registries
        .first()
        .expect("registry row exists");
    assert_eq!(registry.registry_id, "plugin-registry-fixture");
    assert_eq!(registry.project_id, "demo_project");
    assert_eq!(registry.run_id, "run-plugin-registry-fixture");
    assert_eq!(
            registry.generated_state["trackedPolicy"],
            json!("fixture-scoped sample evidence may be tracked; generated runtime outputs remain ignored")
        );
    assert!(registry.blocked_reasons.iter().any(|reason| reason
            == "blocked-command-panel:manifest requested executable command authority outside the v1 declarative catalog"));

    let dashboard_panel = registry
        .plugins
        .iter()
        .find(|plugin| plugin.plugin_id == "read-only-dashboard-panel")
        .expect("dashboard plugin row exists");
    assert_eq!(
        dashboard_panel.manifest_hash,
        "fnv1a64-canonical-json-v1:1111222233334444"
    );
    assert_eq!(dashboard_panel.validation_status, "valid");
    assert_eq!(dashboard_panel.compatibility_status, "compatible");
    assert_eq!(dashboard_panel.declared_capabilities, ["dashboardPanel"]);
    assert_eq!(
        dashboard_panel.extension_points,
        ["dashboard.panels.readOnly"]
    );
    assert_eq!(
            dashboard_panel.evidence_refs,
            ["runs/plugin-registry-fixture/plugin-evidence/read-only-dashboard-panel.validation.json"]
        );
    assert_eq!(dashboard_panel.dashboard_panels.len(), 1);
    let descriptor = &dashboard_panel.dashboard_panels[0];
    assert_eq!(descriptor.panel_id, "plugin-registry-summary");
    assert_eq!(descriptor.title, "Plugin registry summary");
    assert_eq!(descriptor.data_source_key, "pluginRegistry.summary");
    assert_eq!(descriptor.template_ref, "pluginRegistrySummaryCard");
    assert_eq!(descriptor.layout_hint, "summary");
    assert_eq!(descriptor.display_hints, ["compact", "blocked-count"]);
    assert!(descriptor.boundary.contains("no JavaScript"));

    let blocked_panel = registry
        .plugins
        .iter()
        .find(|plugin| plugin.plugin_id == "blocked-command-panel")
        .expect("blocked plugin row exists");
    assert_eq!(blocked_panel.validation_status, "blocked");
    assert_eq!(blocked_panel.compatibility_status, "incompatible");
    assert_eq!(
        blocked_panel.declared_capabilities,
        ["studioInspectorPanel"]
    );
    assert_eq!(
        blocked_panel.extension_points,
        ["studio.inspector.readOnly"]
    );
    assert!(blocked_panel
        .blocked_reasons
        .iter()
        .any(|reason| reason.contains("executable command authority")));

    fs::remove_dir_all(root).expect("fixture removed");
}

