#[test]
fn dashboard_journal_read_model_links_evidence_verdict_and_mutations() {
    let (root, artifacts) = create_test_run("dashboard-journal-read-model");
    fs::write(
            artifacts.run_dir.join("verdict.json"),
            "{\"status\":\"failed\",\"summary\":\"fixture journal failure\",\"failures\":[{\"kind\":\"assertion_failed\"}]}\n",
        )
        .expect("verdict written");
    fs::create_dir_all(artifacts.run_dir.join("evidence/workers/worker-1"))
        .expect("worker evidence dir");
    fs::write(
        artifacts
            .run_dir
            .join("evidence/workers/worker-1/world-state.json"),
        "{\"object\":{\"x\":40}}\n",
    )
    .expect("world state written");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-world-state",
        "application/json",
        "evidence/workers/worker-1/world-state.json",
        json!({ "probe_call": "getWorldState", "worker_id": "worker-1" }),
    )
    .expect("world state indexed");
    let proposal = create_mutation_proposal(
        &artifacts.run_dir,
        MutationProposalInput {
            reason: "fixture failure".to_string(),
            evidence_id: "fixture-world-state".to_string(),
            target: "seeds/platformer.yaml".to_string(),
            path: "scenarios.bootstrap-smoke.assertions".to_string(),
            from: "x == -1".to_string(),
            to: "x == 40".to_string(),
        },
    )
    .expect("mutation proposal created");
    fs::write(
            artifacts.run_dir.join("journal.md"),
            format!(
                "# Ouroforge Run Journal\n\n## Hypothesis\n\n- Validate the failure links.\n\n## Observations\n\n- Evidence `fixture-world-state` at `evidence/workers/worker-1/world-state.json`.\n\n## Verdict Summary\n\n- Status: `failed`\n- Summary: fixture journal failure\n\n## Failed Criteria\n\n- `assertion_failed`: fixture\n\n## Next Mutation\n\n- `{}`: inspect proposal.\n",
                proposal.id
            ),
        )
        .expect("journal written");

    let model = read_dashboard_run(&artifacts.run_dir).expect("dashboard run reads");
    assert!(model.journal_view.exists);
    assert_eq!(model.journal_view.path, "journal.md");
    assert_eq!(model.journal_view.summary, "fixture journal failure");
    assert!(model
        .journal_view
        .entries
        .iter()
        .any(|entry| entry.category == "hypothesis"));
    assert!(model
        .journal_view
        .entries
        .iter()
        .any(|entry| entry.category == "observation"
            && entry
                .evidence_refs
                .contains(&"evidence/workers/worker-1/world-state.json".to_string())));
    assert!(model
        .journal_view
        .entries
        .iter()
        .any(|entry| entry.category == "verdict"
            && entry.verdict_refs.contains(&"verdict.json".to_string())));
    assert!(model.journal_view.entries.iter().any(
        |entry| entry.category == "next_mutation" && entry.mutation_refs.contains(&proposal.id)
    ));
    assert!(model
        .journal_view
        .evidence_refs
        .contains(&"evidence/workers/worker-1/world-state.json".to_string()));
    assert!(model
        .journal_view
        .verdict_refs
        .contains(&"verdict.json".to_string()));
    assert!(model.journal_view.mutation_refs.contains(&proposal.id));

    fs::remove_dir_all(root).expect("fixture removed");
}

#[test]
fn dashboard_and_journal_summarize_scene3d_assertion_evidence_refs() {
    let (root, artifacts) = create_test_run("dashboard-scene3d-assertion-summary");
    write_scenario_result_fixture(&artifacts.run_dir, "failed");
    let probe_path = "evidence/scenarios/bootstrap-smoke/scene3d-probe-evidence.json";
    let render_path = "evidence/scenarios/bootstrap-smoke/scene3d-render-evidence.json";
    fs::write(
        artifacts.run_dir.join(probe_path),
        serde_json::to_string_pretty(&json!({
            "schemaVersion": "ouroforge.scene3d-runtime-probe.v1",
            "present": true,
            "status": "present",
            "nodeCount": 2
        }))
        .expect("probe evidence serializes"),
    )
    .expect("probe evidence written");
    fs::write(
        artifacts.run_dir.join(render_path),
        serde_json::to_string_pretty(&json!({
            "schemaVersion": "ouroforge.scene3d-render-smoke.v1",
            "present": true,
            "visibleObjectCount": 0,
            "failedObjectCount": 1
        }))
        .expect("render evidence serializes"),
    )
    .expect("render evidence written");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-scene3d-probe",
        "application/json",
        probe_path,
        json!({ "artifact": "scene3d_probe", "scenario_id": "bootstrap-smoke" }),
    )
    .expect("probe indexed");
    add_evidence_artifact(
        &artifacts.run_dir,
        "fixture-scene3d-render",
        "application/json",
        render_path,
        json!({ "artifact": "scene3d_render", "scenario_id": "bootstrap-smoke" }),
    )
    .expect("render indexed");
    let result_path = artifacts
        .run_dir
        .join("evidence/scenarios/bootstrap-smoke/scenario-result.json");
    let mut result = read_json_value(&result_path).expect("scenario result reads");
    result["evidence"]["scene3d_probe"] = json!(probe_path);
    result["evidence"]["scene3d_render"] = json!(render_path);
    result["assertions"] = json!([
        {
            "target": "world_state",
            "path": "tick",
            "operator": "exists",
            "expected": false,
            "actual": null,
            "passed": true,
            "evidence_ref": "evidence/scenarios/bootstrap-smoke/world-state.json"
        },
        {
            "target": "scene3d_probe",
            "path": "status",
            "operator": "equals",
            "expected": "present",
            "actual": "present",
            "passed": true,
            "evidence_ref": probe_path
        },
        {
            "target": "scene3d_render",
            "path": "visibleObjectCount",
            "operator": "greaterThan",
            "expected": 0,
            "actual": 0,
            "passed": false,
            "evidence_ref": render_path
        }
    ]);
    fs::write(
        &result_path,
        serde_json::to_string_pretty(&result).expect("scenario result serializes"),
    )
    .expect("scenario result updated");
    evaluate_run(&artifacts.run_dir).expect("verdict evaluates");

    let journal = update_journal(&artifacts.run_dir).expect("journal updates");
    let model = read_dashboard_run(&artifacts.run_dir).expect("dashboard run reads");

    assert!(journal.contains("## 3D Scenario Assertion Evidence"));
    assert!(journal.contains("bounded local 3D scenario QA evidence only"));
    assert!(journal.contains("`scene3d_probe`"));
    assert!(journal.contains("`scene3d_render`"));
    assert!(journal.contains(render_path));
    assert_eq!(model.scenario_assertions.total_count, 3);
    assert_eq!(model.scenario_assertions.scene3d_count, 2);
    assert_eq!(model.scenario_assertions.scene3d_failed_count, 1);
    assert!(model
        .scenario_assertions
        .evidence_refs
        .contains(&probe_path.to_string()));
    assert!(model
        .scenario_assertions
        .evidence_refs
        .contains(&render_path.to_string()));
    assert!(model.scenario_assertions.targets.iter().any(|target| {
        target.id == "world_state" && target.total_count == 1 && target.passed_count == 1
    }));
    assert!(model.scenario_assertions.targets.iter().any(|target| {
        target.id == "scene3d_render"
            && target.failed_count == 1
            && target.evidence_refs.contains(&render_path.to_string())
    }));
    assert!(model
        .journal_view
        .entries
        .iter()
        .any(|entry| entry.heading == "3D Scenario Assertion Evidence"
            && entry.evidence_refs.contains(&render_path.to_string())));

    fs::remove_dir_all(root).expect("fixture removed");
}

