fn json_path_equals(path: &str, expected: serde_json::Value) -> JsonPathAssertion {
    json_path_assertion(path, |assertion| {
        assertion.equals = Some(expected);
    })
}

fn json_path_assertion(
    path: &str,
    configure: impl FnOnce(&mut JsonPathAssertion),
) -> JsonPathAssertion {
    let mut assertion = JsonPathAssertion {
        path: path.to_string(),
        equals: None,
        not_equals: None,
        exists: None,
        contains: None,
        greater_than: None,
        less_than: None,
        count_equals: None,
        count_greater_than: None,
        count_less_than: None,
        contains_type: None,
    };
    configure(&mut assertion);
    assertion
}

#[allow(clippy::too_many_arguments)]
fn assertion_sources_for_test<'a>(
    world_state: &'a serde_json::Value,
    frame_stats: &'a serde_json::Value,
    runtime_events: &'a serde_json::Value,
    world_flags: &'a serde_json::Value,
    physics_evidence: &'a serde_json::Value,
    performance_metrics: &'a serde_json::Value,
    console_errors: &'a serde_json::Value,
    collision_evidence: &'a serde_json::Value,
    audio_evidence: &'a serde_json::Value,
    animation_evidence: &'a serde_json::Value,
    vfx_evidence: &'a serde_json::Value,
    scene3d_camera: &'a serde_json::Value,
    scene3d_animation: &'a serde_json::Value,
    scene3d_probe: &'a serde_json::Value,
    scene3d_transform: &'a serde_json::Value,
    scene3d_render: &'a serde_json::Value,
    scene3d_collision: &'a serde_json::Value,
) -> ScenarioAssertionSources<'a> {
    ScenarioAssertionSources {
        world_state: AssertionSource {
            value: world_state,
            evidence_ref: "evidence/world-state.json",
        },
        frame_stats: AssertionSource {
            value: frame_stats,
            evidence_ref: "evidence/frame-stats.json",
        },
        runtime_events: AssertionSource {
            value: runtime_events,
            evidence_ref: "evidence/cdp-trace-summary.json",
        },
        world_flags: AssertionSource {
            value: world_flags,
            evidence_ref: "evidence/world-state.json",
        },
        physics_evidence: AssertionSource {
            value: physics_evidence,
            evidence_ref: "evidence/world-state.json",
        },
        performance_metrics: AssertionSource {
            value: performance_metrics,
            evidence_ref: "evidence/performance-metrics.json",
        },
        console_errors: AssertionSource {
            value: console_errors,
            evidence_ref: "evidence/console-log.json",
        },
        collision_evidence: AssertionSource {
            value: collision_evidence,
            evidence_ref: "evidence/world-state.json",
        },
        audio_evidence: AssertionSource {
            value: audio_evidence,
            evidence_ref: "evidence/world-state.json",
        },
        animation_evidence: AssertionSource {
            value: animation_evidence,
            evidence_ref: "evidence/world-state.json",
        },
        vfx_evidence: AssertionSource {
            value: vfx_evidence,
            evidence_ref: "evidence/world-state.json",
        },
        transition_evidence: AssertionSource {
            value: world_state.get("transitionEvents").unwrap_or(world_state),
            evidence_ref: "evidence/transition-evidence.json",
        },
        scene3d_camera: AssertionSource {
            value: scene3d_camera,
            evidence_ref: "evidence/scene3d-camera.json",
        },
        scene3d_animation: AssertionSource {
            value: scene3d_animation,
            evidence_ref: "evidence/scene3d-animation.json",
        },
        scene3d_probe: AssertionSource {
            value: scene3d_probe,
            evidence_ref: "evidence/scene3d-probe.json",
        },
        scene3d_transform: AssertionSource {
            value: scene3d_transform,
            evidence_ref: "evidence/scene3d-transforms.json",
        },
        scene3d_render: AssertionSource {
            value: scene3d_render,
            evidence_ref: "evidence/scene3d-render.json",
        },
        scene3d_collision: AssertionSource {
            value: scene3d_collision,
            evidence_ref: "evidence/scene3d-collision.json",
        },
    }
}

fn test_png_bytes(width: u32, height: u32) -> Vec<u8> {
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"\x89PNG\r\n\x1a\n");
    bytes.extend_from_slice(&13u32.to_be_bytes());
    bytes.extend_from_slice(b"IHDR");
    bytes.extend_from_slice(&width.to_be_bytes());
    bytes.extend_from_slice(&height.to_be_bytes());
    bytes.extend_from_slice(&[8, 6, 0, 0, 0]);
    bytes.extend_from_slice(&0u32.to_be_bytes());
    bytes
}

fn create_test_run(prefix: &str) -> (PathBuf, RunArtifacts) {
    let root = unique_temp_dir(prefix);
    fs::create_dir_all(&root).expect("temp root exists");
    let seed_path = root.join("seed.yaml");
    fs::write(&seed_path, VALID_SEED).expect("seed written");
    let runs_root = root.join("runs");
    let artifacts = create_run(&seed_path, &runs_root).expect("run artifacts created");
    (root, artifacts)
}

fn create_project_test_run(root: &Path, scenario_ids: &[&str]) -> RunArtifacts {
    let seed_path = root.join("seed.yaml");
    if !seed_path.exists() {
        fs::write(&seed_path, VALID_SEED).expect("seed written");
    }
    let artifacts = create_run(&seed_path, root.join("runs")).expect("run artifacts created");
    write_fixture_project_context(&artifacts.run_dir, scenario_ids);
    artifacts
}

