fn create_scene_only_mutation_fixture(
    prefix: &str,
) -> (PathBuf, RunArtifacts, MutationProposal, PathBuf, SceneHash) {
    let (root, artifacts) = create_test_run(prefix);
    let scene_path = root.join("scene.json");
    fs::write(
        &scene_path,
        include_str!("../../../examples/game-runtime/scene.json"),
    )
    .expect("scene written");
    add_evidence_artifact(
        &artifacts.run_dir,
        "scene-only-mutation-evidence",
        "application/json",
        "evidence/scene-only-mutation.json",
        json!({ "source": "scene-only-mutation-test" }),
    )
    .expect("evidence indexed");
    let proposal = create_mutation_proposal(
        &artifacts.run_dir,
        MutationProposalInput {
            reason: "scene-only mutation fixture".to_string(),
            evidence_id: "scene-only-mutation-evidence".to_string(),
            target: scene_path.to_string_lossy().to_string(),
            path: "components.transform.x".to_string(),
            from: "32".to_string(),
            to: "48".to_string(),
        },
    )
    .expect("proposal created");
    let scene = read_scene(&scene_path).expect("scene reads");
    let before_hash = hash_scene_document(&scene).expect("scene hashes");
    (root, artifacts, proposal, scene_path, before_hash)
}

fn write_scene_mutation_patch_draft(
    run_dir: &Path,
    proposal: &MutationProposal,
) -> PatchDraftArtifact {
    let run = read_json_value(run_dir.join("run.json")).expect("run reads");
    let run_id = json_string(&run, "id").unwrap_or_else(|| "run-review-gated".to_string());
    let artifact = PatchDraftArtifact {
        schema_version: "1".to_string(),
        run_id,
        drafts: vec![PatchDraft {
            id: "patch-draft-scene-apply-1".to_string(),
            proposal_id: proposal.id.clone(),
            classification_id: "classification-scene-apply-1".to_string(),
            lifecycle_state: PatchDraftState::Drafted,
            target_path: "scenes/review-gated-apply.scene.json".to_string(),
            rationale: "scene-only mutation draft reviewed before apply".to_string(),
            evidence_refs: vec!["evidence/scene-only-mutation.json".to_string()],
            draft_text: "scene-only edit draft; no source patch apply".to_string(),
        }],
    };
    write_patch_draft_artifact(run_dir, &artifact).expect("patch draft writes");
    artifact
}

fn scene_apply_operation(
    proposal: &MutationProposal,
    scene_path: &Path,
    before_hash: SceneHash,
    review_decision_id: Option<String>,
) -> SceneOnlyMutationOperation {
    SceneOnlyMutationOperation {
        schema_version: "scene-only-mutation-v1".to_string(),
        proposal_id: proposal.id.clone(),
        target_scene_path: scene_path.to_string_lossy().to_string(),
        project: None,
        edit: SceneEdit {
            entity_id: "player".to_string(),
            path: "components.transform.x".to_string(),
            value: json!(48),
        },
        review_decision_id,
        expected_before_scene_hash: before_hash,
        validation_required: true,
    }
}

fn accepted_scene_apply_decision(
    run_dir: &Path,
    draft: &PatchDraftArtifact,
    proposal: &MutationProposal,
    expected_hashes: Option<MutationReviewExpectedHashes>,
) -> MutationReviewDecision {
    append_mutation_review_decision(
        run_dir,
        MutationReviewDecisionInput {
            patch_draft_id: draft.drafts[0].id.clone(),
            proposal_id: Some(proposal.id.clone()),
            state: MutationReviewState::Accepted,
            reviewer_type: Some(MutationReviewReviewerType::Human),
            reason: "manual review accepted scene-only mutation application".to_string(),
            evidence_refs: vec!["evidence/scene-only-mutation.json".to_string()],
            reviewer: "test-reviewer".to_string(),
            expected_hashes,
            guardrail_checklist: Some(Default::default()),

            source_patch_review: None,
        },
    )
    .expect("accepted decision appends")
}

fn current_mutation_review_expected_hashes(run_dir: &Path) -> MutationReviewExpectedHashes {
    MutationReviewExpectedHashes {
        proposal_index_hash: Some(
            canonical_json_digest(json!(read_mutation_proposals(run_dir).unwrap())).unwrap(),
        ),
        patch_draft_hash: Some(
            canonical_json_digest(json!(read_patch_draft_artifact(run_dir).unwrap())).unwrap(),
        ),
        evidence_index_hash: Some(
            canonical_json_digest(json!(read_evidence_index(run_dir).unwrap())).unwrap(),
        ),
    }
}

fn create_project_scene_only_mutation_fixture(
    prefix: &str,
) -> (
    PathBuf,
    RunArtifacts,
    MutationProposal,
    PathBuf,
    SceneHash,
    ProjectSceneMutationContext,
) {
    let root = unique_temp_dir(prefix);
    let project_root = root.join("project");
    create_minimal_2d_project_scaffold(&project_root).expect("project scaffolded");
    let scene_path = project_root.join("scenes/main.scene.json");
    let seed_path = project_root.join("seeds/platformer.yaml");
    let artifacts = create_run(&seed_path, root.join("runs")).expect("run artifacts created");
    add_evidence_artifact(
        &artifacts.run_dir,
        "project-scene-only-mutation-evidence",
        "application/json",
        "evidence/project-scene-only-mutation.json",
        json!({ "source": "project-scene-only-mutation-test" }),
    )
    .expect("evidence indexed");
    let proposal = create_mutation_proposal(
        &artifacts.run_dir,
        MutationProposalInput {
            reason: "project scene-only mutation fixture".to_string(),
            evidence_id: "project-scene-only-mutation-evidence".to_string(),
            target: scene_path.to_string_lossy().to_string(),
            path: "components.transform.x".to_string(),
            from: "32".to_string(),
            to: "48".to_string(),
        },
    )
    .expect("proposal created");
    let scene = read_scene(&scene_path).expect("scene reads");
    let scene_hash = hash_scene_document(&scene).expect("scene hashes");
    let manifest_path = project_root.join(PROJECT_MANIFEST_FILE_NAME);
    let manifest_hash = hash_project_manifest_file(&manifest_path).expect("manifest hashes");
    let project_context = ProjectSceneMutationContext {
        project_id: "minimal_2d".to_string(),
        manifest_path: manifest_path.to_string_lossy().to_string(),
        manifest_hash,
        scene_path: "scenes/main.scene.json".to_string(),
        scene_hash: scene_hash.clone(),
    };
    (
        root,
        artifacts,
        proposal,
        scene_path,
        scene_hash,
        project_context,
    )
}

fn unique_temp_dir(prefix: &str) -> PathBuf {
    std::env::temp_dir().join(format!(
        "{prefix}-{}-{}",
        std::process::id(),
        unix_millis().expect("time works")
    ))
}
